export const UFSC_GERADO_2026_QUESTIONS: any[] = [
  { id: 'ufsc_gerado26_001', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Na classificação tomográfica de Balthazar para pancreatite aguda, o grau E corresponde a:', options: ['duas ou mais coleções peripancreáticas mal definidas ou presença de gás no retroperitônio.', 'pâncreas normal.', 'aumento focal ou difuso do pâncreas, incluindo irregularidades no contorno.', 'anormalidades pancreáticas intrínsecas associadas a alterações na gordura peripancreática.', 'uma única coleção líquida peripancreática mal definida.'], correctIndex: 0, explanation: 'O grau E de Balthazar corresponde a duas ou mais coleções peripancreáticas mal definidas ou presença de gás retroperitoneal, refletindo necrose extensa e maior gravidade. Pâncreas normal corresponde ao grau A; aumento focal/difuso do contorno corresponde ao grau B; alterações na gordura peripancreática correspondem ao grau C; uma única coleção mal definida corresponde ao grau D, grau de gravidade intermediário inferior ao E.' },
  { id: 'ufsc_gerado26_002', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Em relação às lesões cáusticas do esôfago por ingestão de substância alcalina, a endoscopia digestiva alta:', options: ['deve ser realizada nas primeiras 24-48 horas para avaliar a extensão da lesão, evitando-se a manipulação excessiva pelo risco de perfuração em lesões profundas.', 'está sempre contraindicada em qualquer momento após a ingestão da substância cáustica.', 'deve ser postergada obrigatoriamente para depois de 30 dias da ingestão, independente do quadro clínico.', 'não tem qualquer papel na avaliação de lesões cáusticas esofágicas.', 'deve ser realizada apenas se houver estenose esofágica já estabelecida clinicamente.'], correctIndex: 0, explanation: 'A endoscopia precoce (24-48 horas) permite avaliar a extensão e gravidade da lesão cáustica, orientando a conduta, mas deve ser feita com cautela pelo risco de perfuração em lesões profundas. Contraindicar em qualquer momento ignora seu papel diagnóstico importante; postergar obrigatoriamente para 30 dias atrasa a avaliação inicial necessária; afirmar ausência de papel contraria sua utilidade estabelecida; esperar estenose já estabelecida perde a janela de avaliação da lesão aguda.' },
  { id: 'ufsc_gerado26_003', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Em relação aos incidentalomas de suprarrenal descobertos por métodos de imagem, uma massa de 4,5cm, com características de imagem indeterminadas e função hormonal não avaliada, deve ter como conduta inicial:', options: ['avaliação hormonal completa (rastreamento de feocromocitoma, síndrome de Cushing subclínica e hiperaldosteronismo) antes de qualquer decisão terapêutica.', 'ressecção cirúrgica imediata, independente de qualquer avaliação hormonal.', 'observação isolada por 5 anos, sem qualquer avaliação hormonal ou radiológica adicional.', 'biópsia percutânea como primeiro passo, antes de qualquer avaliação hormonal.', 'radioterapia empírica, sem qualquer investigação adicional.'], correctIndex: 0, explanation: 'Todo incidentaloma adrenal deve ser avaliado hormonalmente antes de qualquer decisão terapêutica, para excluir tumores funcionantes (feocromocitoma deve ser excluído antes de qualquer biópsia, pelo risco de crise hipertensiva). Ressecção imediata sem avaliação hormonal é perigosa, especialmente se houver feocromocitoma não diagnosticado; observação isolada por 5 anos sem avaliação hormonal ignora achado relevante; biópsia percutânea antes de excluir feocromocitoma é contraindicada pelo risco de crise hipertensiva; radioterapia empírica não é conduta inicial apropriada sem diagnóstico definido.' },
  { id: 'ufsc_gerado26_004', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'O tipo histológico mais comum de sarcoma retroperitoneal em adultos é:', options: ['lipossarcoma.', 'rabdomiossarcoma.', 'angiossarcoma.', 'sarcoma sinovial.', 'osteossarcoma extraesquelético.'], correctIndex: 0, explanation: 'O lipossarcoma é o tipo histológico mais comum entre os sarcomas retroperitoneais em adultos. O rabdomiossarcoma é mais comum em crianças e em outras localizações; o angiossarcoma é tipo raro e agressivo, não o mais comum nessa localização; o sarcoma sinovial acomete tipicamente extremidades próximas a articulações; o osteossarcoma extraesquelético é entidade rara, não a mais comum no retroperitônio.' },
  { id: 'ufsc_gerado26_005', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Em relação ao uso do dióxido de carbono para pneumoperitônio na videolaparoscopia, assinale a alternativa CORRETA:', options: ['é preferido por ser um gás não inflamável e altamente solúvel no sangue, facilitando sua eliminação pela via respiratória.', 'é preferido exclusivamente por seu baixo custo, sem qualquer vantagem fisiológica sobre outros gases.', 'não tem qualquer efeito sobre o equilíbrio ácido-base do paciente durante o procedimento.', 'é utilizado por não causar qualquer repercussão hemodinâmica durante a insuflação.', 'é contraindicado em qualquer procedimento laparoscópico devido ao risco de embolia gasosa.'], correctIndex: 0, explanation: 'O CO2 é preferido por não ser inflamável (permitindo uso seguro com eletrocautério) e por sua alta solubilidade sanguínea, facilitando sua eliminação pela ventilação, reduzindo o risco de embolia gasosa grave em comparação a gases menos solúveis. Não é escolhido apenas pelo custo, havendo vantagens fisiológicas reais; pode causar acidose respiratória por absorção sistêmica, exigindo ajuste ventilatório; pode causar repercussão hemodinâmica pela pressão intra-abdominal aumentada; não é contraindicado em procedimentos laparoscópicos, sendo o gás padrão utilizado.' },
  { id: 'ufsc_gerado26_006', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Em relação ao pseudocisto pancreático na infância, assinale a alternativa CORRETA:', options: ['a principal causa é o trauma abdominal, e a maioria dos casos resolve-se espontaneamente com tratamento conservador.', 'a principal causa é a pancreatite biliar litiásica, assim como no adulto.', 'a maioria dos casos exige drenagem cirúrgica imediata, independente do tamanho ou dos sintomas.', 'não tem qualquer relação com trauma abdominal na infância.', 'deve ser sempre tratado com pancreatectomia total, independente da extensão.'], correctIndex: 0, explanation: 'Na infância, o trauma abdominal é a principal causa de pseudocisto pancreático, e a maioria resolve-se espontaneamente com tratamento conservador. A pancreatite biliar litiásica é causa mais comum no adulto, não na criança; drenagem cirúrgica imediata não é necessária na maioria dos casos, reservada a complicações ou pseudocistos persistentes/sintomáticos; há sim relação relevante com trauma abdominal nessa faixa etária; pancreatectomia total é conduta desproporcional para essa condição, na maioria das vezes autolimitada.' },
  { id: 'ufsc_gerado26_007', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'A tríade de Whipple (hipoglicemia com sintomas neuroglicopênicos, glicemia baixa documentada durante os sintomas e melhora com a administração de glicose) está classicamente associada a qual tumor?', options: ['Insulinoma.', 'Gastrinoma.', 'Glucagonoma.', 'VIPoma.', 'Somatostatinoma.'], correctIndex: 0, explanation: 'A tríade de Whipple é classicamente associada ao insulinoma, tumor produtor de insulina que causa hipoglicemia sintomática revertida pela administração de glicose. O gastrinoma causa síndrome de Zollinger-Ellison, com úlceras pépticas recorrentes, não hipoglicemia; o glucagonoma cursa com hiperglicemia e eritema necrolítico migratório; o VIPoma cursa com diarreia aquosa profusa (síndrome de Verner-Morrison); o somatostatinoma cursa com diabetes, colelitíase e esteatorreia.' },
  { id: 'ufsc_gerado26_008', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'O fator de risco mais potente para o desenvolvimento de hepatocarcinoma é:', options: ['cirrose hepática, independentemente da etiologia de base.', 'obesidade isolada, sem qualquer doença hepática de base.', 'uso esporádico e moderado de álcool, sem cirrose estabelecida.', 'esteatose hepática simples, sem fibrose ou inflamação associada.', 'hepatite viral aguda autolimitada, sem cronificação.'], correctIndex: 0, explanation: 'A cirrose hepática, independentemente da etiologia de base (viral, alcoólica, metabólica), é o fator de risco mais potente para o desenvolvimento de hepatocarcinoma, justificando o rastreamento periódico nesses pacientes. Obesidade isolada sem doença hepática de base tem risco muito menor; uso esporádico e moderado de álcool sem cirrose não confere esse risco elevado; esteatose simples sem fibrose tem risco bem menor que a cirrose estabelecida; hepatite aguda autolimitada sem cronificação não é fator de risco relevante para hepatocarcinoma.' },
  { id: 'ufsc_gerado26_009', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 45 anos, com massa abdominal pulsátil identificada em exame de rotina, ultrassonografia confirmando aneurisma de aorta abdominal infrarrenal de 4,0cm, assintomático, sem história familiar de aneurisma. Assinale a conduta MAIS ADEQUADA:', options: ['acompanhamento ultrassonográfico seriado, sem indicação cirúrgica no momento.', 'correção cirúrgica imediata, independente do tamanho abaixo do limiar de intervenção.', 'anticoagulação plena isolada, sem qualquer acompanhamento por imagem.', 'embolização isolada, independente do tamanho e da ausência de sintomas.', 'observação sem qualquer exame de imagem de seguimento.'], correctIndex: 0, explanation: 'Aneurisma abaixo do limiar cirúrgico (geralmente 5,5cm) e assintomático é conduzido com acompanhamento ultrassonográfico seriado, sem indicação cirúrgica imediata. Corrigir cirurgicamente abaixo do limiar expõe a risco cirúrgico desnecessário; anticoagulação plena não trata o risco de rotura nem substitui o seguimento por imagem; embolização isolada não é indicada abaixo do limiar de intervenção; não seguir com imagem é perigoso, pois o aneurisma pode crescer sem monitorização.' },
  { id: 'ufsc_gerado26_010', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 38 anos, com massa cervical anterior palpável, ultrassonografia com nódulo tireoidiano de 2,3cm, hipoecoico, com microcalcificações e margens irregulares. Assinale a conduta MAIS ADEQUADA:', options: ['punção aspirativa por agulha fina guiada por ultrassonografia.', 'tireoidectomia total imediata, sem qualquer confirmação citológica prévia.', 'observação clínica isolada por 24 meses, sem qualquer investigação adicional.', 'radioterapia isolada, sem avaliação cirúrgica ou citológica prévia.', 'cintilografia tireoidiana como único exame necessário, sem punção.'], correctIndex: 0, explanation: 'Nódulo com características ultrassonográficas de alto risco tem indicação de punção aspirativa por agulha fina para definir a conduta. Tireoidectomia sem confirmação citológica é desproporcional; observação isolada por 24 meses ignora características de alto risco; radioterapia não é conduta inicial apropriada; cintilografia não substitui a punção diante dessas características suspeitas.' },
  { id: 'ufsc_gerado26_011', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 55 anos, com abaulamento inguinal esquerdo conhecido há anos, procura atendimento por dor intensa e súbita, náuseas e impossibilidade de redução manual da massa, antes redutível. Assinale a conduta CORRETA:', options: ['correção cirúrgica de urgência, pela suspeita de encarceramento com risco de estrangulamento.', 'tentativa vigorosa e repetida de redução manual, independente do tempo de evolução da dor.', 'alta com anti-inflamatório e retorno ambulatorial eletivo.', 'observação domiciliar até que a massa reduza espontaneamente.', 'antibioticoterapia oral isolada, sem qualquer avaliação cirúrgica.'], correctIndex: 0, explanation: 'Hérnia previamente redutível que se torna irredutível, dolorosa e associada a náuseas sugere encarceramento com risco de estrangulamento, exigindo correção cirúrgica de urgência. Tentativas vigorosas de redução podem reduzir alça já isquêmica, sendo perigosas; alta com anti-inflamatório ignora uma emergência cirúrgica potencial; observação aguardando redução espontânea arrisca necrose intestinal; antibioticoterapia isolada não trata a obstrução mecânica nem o risco de estrangulamento.' },
  { id: 'ufsc_gerado26_012', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 60 anos, com dor abdominal iniciada em região periumbilical, migrando para fossa ilíaca direita, Blumberg positivo, febre de 38,1°C, tomografia com apêndice espessado e estrato periapendicular. Assinale a conduta MAIS ADEQUADA:', options: ['apendicectomia (aberta ou laparoscópica).', 'tratamento antibiótico isolado, dispensando qualquer cirurgia nesse caso.', 'observação isolada por 48 horas, sem tratamento cirúrgico ou antibiótico.', 'colonoscopia de urgência, antes de qualquer decisão terapêutica.', 'apenas analgesia, sem antibioticoterapia ou avaliação cirúrgica.'], correctIndex: 0, explanation: 'Apendicite aguda confirmada por imagem tem indicação de apendicectomia como tratamento padrão-ouro. Tratamento antibiótico isolado é opção apenas em casos muito selecionados; observação isolada por 48 horas aumenta o risco de perfuração; colonoscopia não é indicada na fase aguda pelo risco de perfuração; analgesia isolada não trata o processo infeccioso.' },
  { id: 'ufsc_gerado26_013', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 50 anos, com dor em hipocôndrio direito há 8 horas, febre de 38,4°C, Murphy positivo, ultrassonografia com parede vesicular espessada (4,5mm) e cálculo impactado no colo. Assinale a conduta MAIS ADEQUADA:', options: ['colecistectomia videolaparoscópica precoce, associada a antibioticoterapia.', 'tratamento clínico exclusivo com antibiótico, sem cirurgia em nenhum momento.', 'colecistectomia eletiva após 6 semanas de tratamento clínico exclusivo.', 'CPRE de urgência, independente de sinais de coledocolitíase.', 'observação isolada, sem antibioticoterapia ou cirurgia.'], correctIndex: 0, explanation: 'Colecistite aguda tem indicação de colecistectomia videolaparoscópica precoce associada a antibioticoterapia. Tratamento clínico exclusivo sem cirurgia expõe a risco de recorrência e complicações; postergar a cirurgia para 6 semanas não é a abordagem preferida quando a cirurgia precoce é factível; CPRE não é rotina sem sinais de obstrução de via biliar principal; observação isolada ignora o processo infeccioso agudo.' },
  { id: 'ufsc_gerado26_014', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 42 anos, com hematêmese volumosa, cirrose hepática por álcool, PA 82/54mmHg, endoscopia de urgência com varizes esofágicas sangrantes. Além da ressuscitação volêmica, assinale a conduta MAIS ADEQUADA:', options: ['terlipressina IV associada a ligadura elástica endoscópica e antibioticoterapia profilática.', 'apenas ligadura endoscópica, sem terlipressina ou antibiótico.', 'balão de Sengstaken-Blakemore como primeira medida, antes de qualquer endoscopia.', 'betabloqueador IV em altas doses como principal medida hemostática.', 'apenas transfusão de hemácias, sem qualquer medida hemostática direta.'], correctIndex: 0, explanation: 'Sangramento por varizes esofágicas em cirrótico é tratado com terlipressina, ligadura endoscópica e antibioticoterapia profilática, que reduz mortalidade. Ligadura isolada sem terlipressina e antibiótico não segue o protocolo completo; o balão é medida de resgate temporário, não a primeira antes da endoscopia; betabloqueador IV não é a principal medida hemostática aguda; transfusão isolada sem medida hemostática direta não controla o sangramento ativo.' },
  { id: 'ufsc_gerado26_015', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 65 anos, tabagista, disfagia progressiva primeiro para sólidos e depois líquidos, perda de 10kg, biópsia endoscópica confirmando carcinoma espinocelular em terço médio do esôfago. Assinale a conduta MAIS ADEQUADA antes de definir o tratamento:', options: ['estadiamento com tomografia de tórax/abdome e ecoendoscopia, quando indicada.', 'esofagectomia imediata, sem qualquer estadiamento prévio.', 'radioterapia paliativa isolada, sem investigação estadiadora.', 'quimioterapia isolada sem estadiamento prévio.', 'observação clínica isolada, sem qualquer conduta adicional.'], correctIndex: 0, explanation: 'Após confirmação histológica, o estadiamento é essencial para definir a extensão e estratégia terapêutica. Esofagectomia sem estadiamento pode ser inadequada para o estágio real; radioterapia paliativa isolada sem estadiamento não permite avaliar potencial curativo; quimioterapia isolada sem estadiamento não define adequadamente a estratégia; observação isolada ignora um diagnóstico confirmado de neoplasia maligna.' },
  { id: 'ufsc_gerado26_016', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 47 anos, obesa, com dor intensa em fossa ilíaca esquerda, febre baixa, tomografia com espessamento de parede colônica com divertículos e borramento de gordura pericólica, sem abscesso ou perfuração livre. Assinale a conduta MAIS ADEQUADA:', options: ['tratamento clínico com antibioticoterapia e dieta conforme tolerância.', 'colectomia de urgência, independente da gravidade.', 'colonoscopia de urgência imediata, independente do risco de perfuração.', 'apenas analgesia, sem qualquer antibioticoterapia.', 'observação isolada sem tratamento, aguardando resolução espontânea.'], correctIndex: 0, explanation: 'Diverticulite aguda não complicada é tratada clinicamente com antibioticoterapia e dieta conforme tolerância. Colectomia de urgência é desproporcional para a forma não complicada; colonoscopia na fase aguda é geralmente postergada pelo risco de perfuração; não tratar com antibiótico ignora o processo infeccioso; observação isolada sem tratamento pode permitir progressão para complicações.' },
  { id: 'ufsc_gerado26_017', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 58 anos, com icterícia progressiva indolor, colúria, acolia fecal, tomografia evidenciando massa em cabeça de pâncreas com dilatação de vias biliares. Assinale a conduta de investigação MAIS ADEQUADA:', options: ['colangiorressonância e biópsia guiada por ecoendoscopia, com avaliação de ressecabilidade.', 'apenas analgesia e hidratação, sem investigação de massa pancreática.', 'observação clínica isolada, sem qualquer investigação de imagem.', 'sorologias virais como único exame necessário, sem investigação de massa.', 'colecistectomia isolada, sem investigação da massa pancreática.'], correctIndex: 0, explanation: 'Icterícia indolor progressiva com massa em cabeça de pâncreas é altamente sugestiva de adenocarcinoma de pâncreas, exigindo investigação complementar e avaliação de ressecabilidade. Analgesia isolada não investiga a massa; observação isolada atrasa o diagnóstico; sorologias virais não explicam a massa identificada; colecistectomia isolada não trata nem investiga a neoplasia pancreática.' },
  { id: 'ufsc_gerado26_018', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 30 anos, vítima de ferimento penetrante abdominal por arma branca, instável hemodinamicamente. Assinale a conduta padrão, segundo os princípios de cirurgia de controle de danos:', options: ['controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para momento posterior.', 'reconstrução anatômica completa e definitiva de todas as lesões na primeira intervenção.', 'observação clínica isolada, sem intervenção cirúrgica imediata.', 'anastomoses intestinais múltiplas complexas como prioridade sobre o controle hemorrágico.', 'fechamento definitivo da parede abdominal como prioridade sobre o controle da hemorragia.'], correctIndex: 0, explanation: 'A cirurgia de controle de danos prioriza o controle rápido de hemorragia e contaminação, adiando reconstruções definitivas para depois da estabilização fisiológica. Reconstrução completa na primeira intervenção agrava a tríade letal; observação isolada é inadequada diante de instabilidade e ferimento penetrante; anastomoses complexas e fechamento definitivo antes do controle hemorrágico invertem a prioridade correta.' },
  { id: 'ufsc_gerado26_019', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 60 anos, com massa palpável em quadrante superior externo da mama esquerda, mamografia com lesão espiculada BI-RADS 5. Assinale o próximo passo MAIS ADEQUADO antes de definir a estratégia terapêutica:', options: ['biópsia percutânea (core biopsy) para confirmação histológica.', 'mastectomia radical imediata, sem confirmação histológica prévia.', 'observação clínica com nova mamografia em 12 meses.', 'quimioterapia empírica, sem qualquer biópsia.', 'radioterapia isolada, sem diagnóstico histológico prévio.'], correctIndex: 0, explanation: 'Mesmo com alta suspeição radiológica, a biópsia percutânea é necessária para confirmação histológica antes de definir a estratégia terapêutica. Mastectomia sem confirmação histológica é desproporcional sem diagnóstico definitivo; observação por 12 meses é inadequada diante de lesão de alta suspeição; quimioterapia e radioterapia empíricas sem biópsia tratariam uma doença ainda não confirmada.' },
  { id: 'ufsc_gerado26_020', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 48 anos, com pancreatite aguda grave, evolui no quinto dia com necrose pancreática identificada em tomografia, sem sinais clínicos ou laboratoriais de infecção. Assinale a conduta MAIS APROPRIADA:', options: ['manejo conservador com suporte clínico, sem indicação de intervenção sobre a necrose estéril.', 'necrosectomia cirúrgica imediata, independente de sinais de infecção.', 'antibioticoterapia profilática de rotina para necrose estéril.', 'drenagem percutânea imediata, independente de sinais de infecção.', 'CPRE de urgência, independente de obstrução biliar concomitante.'], correctIndex: 0, explanation: 'Necrose pancreática estéril, sem sinais de infecção, é manejada de forma conservadora, reservando intervenção para necrose infectada ou complicações. Necrosectomia imediata sem sinais de infecção é conduta desproporcional; antibioticoterapia profilática de rotina não é recomendada pelas diretrizes atuais; drenagem percutânea imediata sem sinais de infecção não é indicada; CPRE de urgência é reservada a obstrução biliar concomitante.' },
  { id: 'ufsc_gerado26_021', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 52 anos, com disfagia progressiva e regurgitação de alimentos não digeridos há meses, esofagografia baritada evidenciando dilatação esofágica com afilamento distal em "bico de pássaro". Assinale o diagnóstico e o exame confirmatório MAIS ADEQUADO:', options: ['acalasia; manometria esofágica de alta resolução.', 'espasmo esofágico difuso; endoscopia digestiva alta isolada, sem manometria.', 'divertículo de Zenker; esofagografia isolada, sem outro exame confirmatório.', 'câncer de esôfago; apenas tomografia de tórax, sem endoscopia.', 'refluxo gastroesofágico grave; pHmetria isolada, sem manometria.'], correctIndex: 0, explanation: 'Dilatação esofágica com afilamento distal em "bico de pássaro" é o achado clássico da acalasia, confirmada por manometria esofágica de alta resolução, que evidencia ausência de peristalse e relaxamento inadequado do esfíncter esofágico inferior. O espasmo esofágico difuso teria outro padrão manométrico, e a manometria (não apenas endoscopia) é necessária para diferenciação; o divertículo de Zenker localiza-se na hipofaringe, com apresentação distinta; o câncer de esôfago exigiria biópsia endoscópica para confirmação, não apenas tomografia; o refluxo grave não explica esse padrão radiológico específico de acalasia.' },
  { id: 'ufsc_gerado26_022', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 55 anos, com massa testicular indolor de crescimento progressivo, ultrassonografia confirmando lesão sólida intratesticular. Assinale a conduta CORRETA:', options: ['orquiectomia inguinal radical, com dosagem prévia de marcadores tumorais.', 'biópsia percutânea transescrotal da lesão como primeira etapa diagnóstica.', 'observação clínica isolada por 6 meses.', 'quimioterapia empírica isolada, sem qualquer avaliação cirúrgica.', 'radioterapia local isolada, sem qualquer confirmação histológica prévia.'], correctIndex: 0, explanation: 'Massa testicular sólida sugestiva de neoplasia tem indicação de orquiectomia inguinal radical, com dosagem prévia de marcadores tumorais, evitando biópsia transescrotal pelo risco de disseminação. Biópsia percutânea transescrotal não é a conduta padrão pelo risco de contaminação da via linfática inguinal; observação isolada atrasa o diagnóstico; quimioterapia e radioterapia empíricas sem diagnóstico histológico não são condutas apropriadas.' },
  { id: 'ufsc_gerado26_023', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 70 anos, com hérnia abdominal na linha média em cicatriz de laparotomia prévia, redutível, sem sinais de encarceramento, sintomática (desconforto ao esforço). Assinale a conduta MAIS ADEQUADA:', options: ['correção cirúrgica eletiva com uso de tela, dada a sintomatologia.', 'observação isolada indefinida, independente dos sintomas relatados.', 'redução manual vigorosa e repetida, sem qualquer avaliação cirúrgica.', 'faixa abdominal isolada como tratamento definitivo, sem cirurgia.', 'antibioticoterapia oral isolada, sem qualquer avaliação cirúrgica.'], correctIndex: 0, explanation: 'Hérnia incisional sintomática tem indicação de correção cirúrgica eletiva, geralmente com uso de tela para reduzir recidiva. Observação indefinida ignora a sintomatologia relatada; redução manual vigorosa sem avaliação cirúrgica não trata definitivamente a hérnia; faixa abdominal isolada não é tratamento definitivo; antibioticoterapia não trata a hérnia, que não é primariamente infecciosa.' },
  { id: 'ufsc_gerado26_024', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 35 anos, previamente hígida, apresenta massa hepática solitária identificada incidentalmente em ultrassonografia, ressonância evidenciando lesão com realce centrípeto característico e cicatriz central, sem sintomas. Assinale o diagnóstico MAIS PROVÁVEL e a conduta:', options: ['hemangioma hepático; observação clínica, sem necessidade de biópsia ou ressecção na maioria dos casos assintomáticos.', 'hepatocarcinoma; ressecção cirúrgica de urgência, independente de outros achados.', 'abscesso hepático; drenagem percutânea de urgência, independente da ausência de sinais infecciosos.', 'cisto hidático; albendazol isolado, sem qualquer outra investigação.', 'metástase hepática; quimioterapia sistêmica imediata, sem investigação do sítio primário.'], correctIndex: 0, explanation: 'Realce centrípeto característico com cicatriz central em lesão hepática incidental assintomática é sugestivo de hemangioma hepático, geralmente conduzido com observação, sem necessidade de biópsia (que pode ser perigosa pelo risco de sangramento) ou ressecção na maioria dos casos assintomáticos. O hepatocarcinoma teria outro padrão de realce e geralmente ocorreria em fígado cirrótico, exigindo confirmação antes de ressecção de urgência; abscesso hepático cursaria com sinais infecciosos sistêmicos, ausentes no caso; cisto hidático teria aspecto cístico característico à imagem, não esse padrão de realce; metástase hepática exigiria identificação do sítio primário antes de iniciar quimioterapia sistêmica.' },
  { id: 'ufsc_gerado26_025', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 62 anos, com sangramento retal intermitente há 2 meses, alteração do hábito intestinal e perda ponderal, colonoscopia evidenciando lesão vegetante estenosante em cólon descendente, biópsia confirmando adenocarcinoma. Assinale a conduta MAIS ADEQUADA antes da cirurgia:', options: ['estadiamento com tomografia de tórax, abdome e pelve, além de dosagem de CEA sérico.', 'colectomia de urgência imediata, sem qualquer estadiamento prévio.', 'quimioterapia neoadjuvante isolada, sem qualquer estadiamento por imagem.', 'observação clínica isolada, sem qualquer conduta adicional.', 'apenas repetição da colonoscopia em 6 meses, sem estadiamento sistêmico.'], correctIndex: 0, explanation: 'Após confirmação histológica de adenocarcinoma colônico, o estadiamento sistêmico com tomografia e CEA sérico é essencial para planejar a estratégia cirúrgica e detectar doença metastática. Colectomia de urgência sem estadiamento prévio pode ser inadequada diante de doença avançada não identificada; quimioterapia neoadjuvante isolada sem estadiamento não é a conduta padrão nesse cenário; observação isolada ignora um diagnóstico confirmado de câncer; repetir a colonoscopia sem estadiamento sistêmico não avalia a extensão da doença.' },
  { id: 'ufsc_gerado26_026', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 50 anos, com dor epigástrica súbita e intensa, abdome em tábua, pneumoperitônio à radiografia de tórax em ortostase, história de uso crônico de anti-inflamatório não esteroidal. Assinale a conduta MAIS ADEQUADA:', options: ['laparotomia (ou videolaparoscopia) de urgência para rafia da perfuração, associada a lavagem da cavidade.', 'tratamento clínico exclusivo com inibidor de bomba de prótons, sem qualquer abordagem cirúrgica.', 'endoscopia digestiva alta de urgência como único procedimento necessário, sem cirurgia.', 'observação clínica isolada por 24 horas, sem qualquer intervenção.', 'antibioticoterapia oral isolada, sem qualquer procedimento cirúrgico.'], correctIndex: 0, explanation: 'Abdome em tábua com pneumoperitônio em paciente com uso crônico de anti-inflamatório sugere úlcera péptica perfurada, exigindo abordagem cirúrgica de urgência para rafia e lavagem peritoneal. Tratamento clínico exclusivo não corrige a perfuração já estabelecida com contaminação peritoneal; endoscopia isolada não trata a perfuração nem a peritonite associada; observação isolada é perigosa diante de abdome agudo perfurativo; antibioticoterapia oral isolada não substitui o controle cirúrgico da fonte de contaminação.' },
  { id: 'ufsc_gerado26_027', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à participação social no Sistema Único de Saúde, prevista pela Lei nº 8.142/1990, assinale a alternativa CORRETA sobre os Conselhos de Saúde:', options: ['são instâncias colegiadas, de caráter permanente e deliberativo, com representação paritária de usuários em relação ao conjunto dos demais segmentos.', 'têm caráter exclusivamente consultivo, sem qualquer poder deliberativo sobre a política de saúde local.', 'são compostos exclusivamente por gestores públicos, sem participação de usuários ou trabalhadores de saúde.', 'reúnem-se apenas quando convocados pelo Ministério da Saúde, sem periodicidade regular estabelecida.', 'não têm qualquer papel na fiscalização da aplicação de recursos financeiros da saúde.'], correctIndex: 0, explanation: 'Os Conselhos de Saúde, previstos pela Lei nº 8.142/1990, são instâncias colegiadas, permanentes e deliberativas, com representação paritária de usuários em relação ao conjunto dos demais segmentos (gestores, prestadores e trabalhadores). Não têm caráter exclusivamente consultivo, tendo poder deliberativo sobre a política de saúde; não são compostos exclusivamente por gestores, sendo essencial a participação de usuários e trabalhadores; têm periodicidade regular de reuniões estabelecida em regimento próprio, não apenas quando convocados; têm papel de fiscalização da aplicação dos recursos financeiros da saúde, sendo essa uma de suas atribuições centrais.' },
  { id: 'ufsc_gerado26_028', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao apoio matricial (matriciamento) prestado pelo Núcleo Ampliado de Saúde da Família (NASF) às equipes de Saúde da Família, assinale a alternativa CORRETA:', options: ['consiste em um arranjo organizacional que oferece suporte técnico-pedagógico e assistencial às equipes de referência, sem substituir o vínculo do usuário com sua equipe de saúde da família.', 'implica a transferência definitiva do cuidado do usuário da equipe de saúde da família para o especialista do NASF.', 'restringe-se ao atendimento individual direto de todos os usuários encaminhados, sem qualquer discussão de caso com a equipe de referência.', 'é aplicável exclusivamente a casos de saúde mental, sem relação com outras áreas de cuidado.', 'dispensa qualquer articulação ou discussão conjunta de caso entre o profissional do NASF e a equipe de saúde da família.'], correctIndex: 0, explanation: 'O matriciamento é arranjo organizacional que oferece suporte técnico-pedagógico e assistencial às equipes de referência, sem substituir o vínculo do usuário com sua equipe de saúde da família, atuando por meio de discussão de casos, atendimento compartilhado e educação permanente. Não implica transferência definitiva do cuidado para o especialista; não se restringe ao atendimento individual direto, sendo a discussão de caso elemento central da metodologia; não é exclusivo de saúde mental, atuando em múltiplas áreas (nutrição, fisioterapia, saúde da mulher, entre outras); depende justamente da articulação e discussão conjunta entre o profissional do NASF e a equipe de referência.' },
  { id: 'ufsc_gerado26_029', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à prevenção quaternária na atenção primária, assinale a alternativa CORRETA:', options: ['busca evitar intervenções médicas desnecessárias ou potencialmente prejudiciais.', 'tem como objetivo aumentar sistematicamente o número de exames solicitados por consulta.', 'aplica-se exclusivamente a pacientes oncológicos em cuidados paliativos.', 'é sinônimo de prevenção terciária, sem qualquer distinção conceitual.', 'não tem qualquer relação com a solicitação racional de exames complementares.'], correctIndex: 0, explanation: 'A prevenção quaternária busca proteger o paciente de intervenções desnecessárias ou potencialmente prejudiciais. Aumentar sistematicamente o número de exames contraria diretamente esse objetivo; não se restringe a pacientes oncológicos paliativos; não é sinônimo de prevenção terciária; tem relação direta com a solicitação racional de exames complementares.' },
  { id: 'ufsc_gerado26_030', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação ao acolhimento com classificação de risco na atenção primária, assinale a alternativa CORRETA:', options: ['busca reorganizar o processo de trabalho para priorizar o atendimento conforme a gravidade clínica e a vulnerabilidade.', 'tem como único critério válido a ordem cronológica de chegada do paciente ao serviço.', 'é aplicável exclusivamente a serviços de urgência hospitalar, nunca à atenção primária.', 'elimina completamente a necessidade de triagem em qualquer nível de atenção.', 'restringe o atendimento apenas a casos de alta gravidade clínica imediata.'], correctIndex: 0, explanation: 'O acolhimento com classificação de risco reorganiza o atendimento priorizando gravidade clínica e vulnerabilidade, não apenas a ordem de chegada. Considerar apenas a ordem cronológica contraria o princípio do modelo; é aplicável também na atenção primária; não elimina a necessidade de triagem, sendo ele próprio um processo de triagem qualificada; não restringe o atendimento apenas a casos graves.' },
  { id: 'ufsc_gerado26_031', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à hierarquização da rede de atenção à saúde no SUS, assinale a alternativa CORRETA:', options: ['organiza os serviços por níveis crescentes de complexidade, com fluxos de referência e contrarreferência entre eles.', 'concentra todo o atendimento exclusivamente em hospitais terciários, independentemente da complexidade do caso.', 'elimina completamente a atenção primária à saúde do sistema.', 'restringe o acesso da população apenas aos serviços privados conveniados.', 'centraliza toda a gestão da saúde exclusivamente no nível federal.'], correctIndex: 0, explanation: 'A hierarquização organiza os serviços por níveis crescentes de complexidade, com fluxos de referência e contrarreferência. Concentrar tudo em hospitais terciários contraria essa lógica; a atenção primária é a porta de entrada preferencial, não sendo eliminada; o SUS não se restringe a serviços privados conveniados; a gestão do SUS é descentralizada, com participação federal, estadual e municipal.' },
  { id: 'ufsc_gerado26_032', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação às ferramentas de abordagem familiar utilizadas na Atenção Primária à Saúde, o genograma e o ecomapa têm como objetivo principal:', options: ['representar graficamente a estrutura familiar e suas relações internas (genograma) e as conexões da família com recursos e sistemas externos (ecomapa), auxiliando na compreensão do contexto do paciente.', 'substituir integralmente a necessidade de exame físico e história clínica do paciente.', 'ser aplicáveis exclusivamente em casos de violência doméstica confirmada, sem uso em outros contextos clínicos.', 'registrar exclusivamente dados antropométricos da família, sem relação com vínculos ou rede de apoio.', 'ser ferramentas de uso restrito a psicólogos, sem aplicação por médicos de família.'], correctIndex: 0, explanation: 'O genograma representa graficamente a estrutura familiar e suas relações internas, enquanto o ecomapa representa as conexões da família com recursos e sistemas externos, auxiliando na compreensão do contexto do paciente. Não substituem o exame físico e a história clínica, sendo ferramentas complementares; são aplicáveis a diversos contextos clínicos, não exclusivos de violência doméstica; não se restringem a dados antropométricos, focando em vínculos e rede de apoio; podem e devem ser utilizados por toda a equipe multiprofissional, incluindo médicos de família, não sendo exclusivos de psicólogos.' },
  { id: 'ufsc_gerado26_033', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Rede de Atenção Psicossocial e ao papel do CAPS, assinale a alternativa CORRETA:', options: ['atua na articulação do cuidado em saúde mental de base territorial e comunitária, com construção de projeto terapêutico singular.', 'tem como estratégia central a internação psiquiátrica prolongada em hospital especializado.', 'restringe-se ao atendimento de urgências psiquiátricas agudas, sem acompanhamento longitudinal.', 'não estabelece qualquer articulação com a atenção primária à saúde.', 'é destinado exclusivamente a pacientes com dependência química.'], correctIndex: 0, explanation: 'O CAPS atua na articulação do cuidado em saúde mental de base territorial e comunitária, construindo projeto terapêutico singular. A Reforma Psiquiátrica preconiza a substituição do modelo hospitalocêntrico pela atenção territorial; o CAPS realiza acompanhamento longitudinal, não se restringindo a urgências agudas; articula-se com a atenção primária; atende diversas condições de saúde mental, não exclusivamente dependência química.' },
  { id: 'ufsc_gerado26_034', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação aos determinantes sociais da saúde, assinale a alternativa CORRETA:', options: ['incluem condições de moradia, renda, escolaridade e acesso a saneamento básico, interagindo com determinantes biológicos.', 'atuam de forma completamente independente dos determinantes biológicos.', 'não têm qualquer relação com políticas intersetoriais de enfrentamento.', 'se restringem exclusivamente a fatores genéticos individuais.', 'são irrelevantes para o planejamento em saúde pública.'], correctIndex: 0, explanation: 'Os determinantes sociais incluem moradia, renda, escolaridade e saneamento, interagindo com determinantes biológicos. Afirmar independência completa ignora essa interação; políticas intersetoriais são resposta ao enfrentamento de determinantes sociais desfavoráveis; determinantes sociais não se restringem a fatores genéticos; são altamente relevantes para o planejamento em saúde pública.' },
  { id: 'ufsc_gerado26_035', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Caderneta de Saúde da Criança e ao acompanhamento do crescimento e desenvolvimento na atenção primária, assinale a alternativa CORRETA:', options: ['permite o registro sistemático de marcos de desenvolvimento, curvas de crescimento e calendário vacinal, facilitando a detecção precoce de desvios.', 'destina-se exclusivamente ao registro de intercorrências agudas, sem relação com desenvolvimento neuropsicomotor.', 'não deve ser utilizada por profissionais de nível médio, sendo exclusiva do médico pediatra.', 'substitui integralmente a necessidade de consultas de puericultura periódicas.', 'é aplicável apenas até os 12 meses de vida, sem uso posterior.'], correctIndex: 0, explanation: 'A Caderneta de Saúde da Criança permite registro sistemático de marcos de desenvolvimento, curvas de crescimento e vacinação, facilitando a detecção precoce de desvios pela equipe de saúde. Não se destina exclusivamente a intercorrências agudas, tendo função de acompanhamento longitudinal; pode e deve ser utilizada por toda a equipe multiprofissional, não exclusiva do pediatra; não substitui as consultas periódicas de puericultura, sendo instrumento complementar de registro; é utilizada além dos 12 meses, acompanhando a criança em fases posteriores do desenvolvimento.' },
  { id: 'ufsc_gerado26_036', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em um estudo de coorte, a incidência de infarto do miocárdio em fumantes foi de 35 por 1.000 pessoas-ano, e em não fumantes foi de 7 por 1.000 pessoas-ano. Assinale o risco relativo e o risco atribuível ao tabagismo, respectivamente:', options: ['5,0 e 28 por 1.000 pessoas-ano.', '0,2 e 28 por 1.000 pessoas-ano.', '5,0 e 42 por 1.000 pessoas-ano.', '0,2 e 7 por 1.000 pessoas-ano.', '5,0 e 7 por 1.000 pessoas-ano.'], correctIndex: 0, explanation: 'O risco relativo é a razão entre as incidências (35/7 = 5,0) e o risco atribuível é a diferença entre elas (35-7 = 28 por 1.000 pessoas-ano). Inverter a razão (0,2) confundiria o risco relativo com seu recíproco; usar 42 como diferença é erro aritmético; usar 7 como risco atribuível repete a incidência dos não fumantes, não a diferença correta.' },
  { id: 'ufsc_gerado26_037', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Um ensaio clínico randomizado mostrou que, para cada 25 pacientes tratados com uma nova estatina em vez de placebo, um evento cardiovascular maior adicional foi evitado ao longo de 5 anos. Assinale o nome dessa medida e seu valor nesse estudo:', options: ['número necessário para tratar (NNT); 25.', 'razão de chances (odds ratio); 25.', 'risco atribuível percentual; 25%.', 'número necessário para causar dano (NNH); 25.', 'razão de prevalências; 25.'], correctIndex: 0, explanation: 'O número necessário para tratar (NNT) representa quantos pacientes precisam ser tratados para evitar um desfecho adicional, sendo 25 nesse caso. A razão de chances é medida de associação distinta, não uma contagem de pacientes a tratar; o risco atribuível percentual é expresso de forma diferente, não como uma contagem direta de pacientes; o NNH (número necessário para causar dano) refere-se a efeitos adversos, não ao benefício descrito no enunciado; a razão de prevalências é medida de estudos transversais, não aplicável a esse desenho de ensaio clínico.' },
  { id: 'ufsc_gerado26_038', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em um teste diagnóstico aplicado a 250 pacientes com a doença e 750 sem a doença, o teste foi positivo em 225 dos doentes e em 75 dos não doentes. Assinale a sensibilidade e a especificidade do teste, respectivamente:', options: ['90% e 90%.', '90% e 75%.', '75% e 90%.', '90% e 25%.', '75% e 75%.'], correctIndex: 0, explanation: 'A sensibilidade é a proporção de doentes corretamente identificados (225/250 = 90%) e a especificidade é a proporção de não doentes corretamente identificados como negativos (675/750 = 90%). As demais combinações não correspondem aos cálculos corretos com os números fornecidos.' },
  { id: 'ufsc_gerado26_039', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em relação à validade de um teste diagnóstico, assinale a alternativa CORRETA sobre o valor preditivo positivo:', options: ['aumenta quanto maior for a prevalência da doença na população testada, mesmo mantendo sensibilidade e especificidade constantes.', 'é uma propriedade intrínseca do teste, independente da prevalência da doença na população.', 'é sempre igual à sensibilidade do teste, independente da prevalência.', 'diminui quanto maior for a prevalência da doença na população testada.', 'não tem qualquer relação matemática com a especificidade do teste.'], correctIndex: 0, explanation: 'O valor preditivo positivo aumenta quanto maior for a prevalência da doença, mesmo mantendo sensibilidade e especificidade constantes, pois a proporção de verdadeiros-positivos entre os testados positivos cresce. Não é propriedade intrínseca do teste, dependendo da prevalência; não é igual à sensibilidade; diminui, não aumenta, com prevalência baixa; tem relação matemática direta com a especificidade, que influencia a taxa de falsos-positivos.' },
  { id: 'ufsc_gerado26_040', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em relação à notificação compulsória de doenças no Brasil, assinale a alternativa CORRETA:', options: ['é obrigação de todo profissional de saúde e de serviços de saúde, públicos ou privados.', 'aplica-se exclusivamente a médicos, excluindo outros profissionais de saúde.', 'é facultativa para doenças de baixo potencial de disseminação.', 'não exige prazo específico para nenhuma doença, independente da gravidade.', 'é atribuição exclusiva do laboratório que realizou o exame diagnóstico.'], correctIndex: 0, explanation: 'A notificação compulsória é obrigação de todo profissional de saúde e de serviços de saúde, públicos ou privados. Não se aplica exclusivamente a médicos, incluindo outros profissionais de saúde; não é facultativa, sendo obrigatória mesmo para doenças de menor potencial de disseminação, ainda que com prazos diferentes; doenças de notificação imediata exigem prazo específico curto; a notificação é atribuição do profissional/serviço de saúde, não exclusiva do laboratório.' },
  { id: 'ufsc_gerado26_041', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Gestante, 33 semanas, com PA 168/108mmHg, cefaleia occipital e escotomas visuais. Assinale a conduta imediata:', options: ['sulfato de magnésio e avaliação para resolução da gestação.', 'repouso domiciliar, sem qualquer medicação.', 'anti-hipertensivo oral ambulatorial isolado.', 'aguardar 48 horas antes de qualquer conduta.', 'apenas analgésico comum para a cefaleia, sem outra intervenção.'], correctIndex: 0, explanation: 'PA muito elevada com sintomas premonitórios caracteriza pré-eclâmpsia grave, exigindo sulfato de magnésio e avaliação para resolução da gestação. Repouso domiciliar sem medicação não trata a gravidade do quadro; anti-hipertensivo oral ambulatorial isolado é insuficiente diante de sinais premonitórios; aguardar 48 horas atrasa perigosamente uma emergência obstétrica; analgésico comum isolado não trata a causa hipertensiva.' },
  { id: 'ufsc_gerado26_042', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Gestante, 30 semanas, hipertensa, com dor abdominal súbita, hipertonia uterina, sangramento vaginal escuro e sofrimento fetal agudo. Assinale o diagnóstico e a conduta:', options: ['descolamento prematuro de placenta; interrupção imediata da gestação.', 'placenta prévia; conduta expectante.', 'rotura uterina espontânea; observação clínica.', 'trabalho de parto normal; acompanhamento sem intervenção.', 'corioamnionite; apenas antibioticoterapia, sem resolução da gestação.'], correctIndex: 0, explanation: 'Dor súbita, hipertonia uterina e sofrimento fetal em gestante hipertensa são clássicos de descolamento prematuro de placenta, exigindo interrupção imediata. Placenta prévia cursa com sangramento indolor sem hipertonia; rotura uterina espontânea é rara sem cicatriz uterina prévia; trabalho de parto normal não cursa com sofrimento fetal agudo associado a hipertonia; corioamnionite cursaria com febre materna.' },
  { id: 'ufsc_gerado26_043', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Puérpera imediata, com sangramento vaginal importante e útero hipotônico à palpação. Assinale a primeira conduta:', options: ['massagem uterina bimanual e ocitocina.', 'histerectomia imediata.', 'apenas observação.', 'curetagem imediata, sem avaliar o tônus uterino.', 'ácido tranexâmico isolado, sem qualquer manobra sobre o útero.'], correctIndex: 0, explanation: 'Atonia uterina, causa mais comum de hemorragia pós-parto, é tratada inicialmente com massagem bimanual e ocitocina. Histerectomia imediata é medida de exceção para casos refratários; observação isolada é perigosa; curetagem sem avaliar o tônus ignora a causa mais provável; ácido tranexâmico pode ser associado, mas não substitui a massagem e o uterotônico.' },
  { id: 'ufsc_gerado26_044', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Gestante Rh negativo, parceiro Rh positivo, 29 semanas, Coombs indireto negativo. Assinale a conduta profilática:', options: ['imunoglobulina anti-D profilática.', 'nenhuma conduta específica.', 'transfusão intrauterina profilática.', 'interrupção antecipada da gestação.', 'dopplervelocimetria de artéria cerebral média isolada, sem qualquer profilaxia medicamentosa.'], correctIndex: 0, explanation: 'Gestante Rh negativo não sensibilizada deve receber imunoglobulina anti-D por volta da 28ª semana para prevenir aloimunização. Não realizar conduta específica expõe ao risco de sensibilização futura; transfusão intrauterina é tratamento de anemia fetal grave já estabelecida, não profilaxia; interrupção antecipada não tem indicação nessa situação; a dopplervelocimetria é usada no acompanhamento de gestantes já sensibilizadas.' },
  { id: 'ufsc_gerado26_045', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 26 anos, com corrimento vaginal amarelo-esverdeado, prurido intenso e colo uterino com aspecto de "morango" ao exame especular. Assinale o agente etiológico MAIS PROVÁVEL e a conduta:', options: ['Trichomonas vaginalis; metronidazol para a paciente e o(s) parceiro(s) sexual(is).', 'Candida albicans; antifúngico tópico isolado, sem tratamento do parceiro.', 'Gardnerella vaginalis; metronidazol, sem necessidade de tratar o parceiro.', 'Chlamydia trachomatis; azitromicina isolada, sem relação com o achado de colo em "morango".', 'papilomavírus humano; apenas seguimento citológico, sem tratamento medicamentoso.'], correctIndex: 0, explanation: 'O colo em aspecto de "morango" associado a corrimento e prurido é achado clássico de tricomoníase, tratada com metronidazol, com necessidade de tratar também o parceiro sexual. Candida causa corrimento em grumos sem esse aspecto de colo; Gardnerella não costuma causar prurido intenso nem esse aspecto de colo; clamídia não é a etiologia mais associada a esse achado específico; HPV não causa corrimento nem prurido dessa forma.' },
  { id: 'ufsc_gerado26_046', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 34 anos, com amenorreia secundária há 8 meses após curetagem uterina puerperal complicada por infecção, histeroscopia evidenciando sinéquias intrauterinas extensas. Assinale o diagnóstico e a conduta:', options: ['síndrome de Asherman; lise histeroscópica das sinéquias, com medidas para prevenir recidiva.', 'síndrome de Sheehan; reposição hormonal hipofisária isolada, sem qualquer procedimento uterino.', 'insuficiência ovariana prematura; apenas terapia hormonal isolada, sem investigação uterina.', 'hiperprolactinemia; agonista dopaminérgico isolado, sem investigação da cavidade uterina.', 'estenose cervical isolada; dilatação cervical ambulatorial, sem investigação da cavidade uterina.'], correctIndex: 0, explanation: 'Amenorreia secundária após curetagem complicada por infecção, com sinéquias intrauterinas à histeroscopia, é o quadro clássico da síndrome de Asherman, tratada com lise histeroscópica das aderências e medidas para prevenir recidiva. A síndrome de Sheehan relaciona-se a necrose hipofisária pós-hemorragia obstétrica grave, com pan-hipopituitarismo, não sinéquias uterinas; a insuficiência ovariana prematura cursaria com hipoestrogenismo e não explicaria as sinéquias identificadas; a hiperprolactinemia não explica o achado histeroscópico de sinéquias; a estenose cervical isolada não explica a extensão das sinéquias intrauterinas identificadas.' },
  { id: 'ufsc_gerado26_047', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 30 anos, com massa dolorosa e flutuante em região vulvar posterior, unilateral, próximo à entrada vaginal, dificultando a marcha e o sentar. Assinale a conduta MAIS ADEQUADA:', options: ['marsupialização ou drenagem cirúrgica do abscesso de glândula de Bartholin, associada a antibioticoterapia conforme o contexto clínico.', 'apenas antibioticoterapia oral isolada, sem qualquer drenagem ou marsupialização.', 'excisão completa da glândula na fase aguda, independente do estado inflamatório local.', 'observação clínica isolada, aguardando drenagem espontânea sem qualquer intervenção.', 'apenas analgesia, sem qualquer conduta sobre a coleção.'], correctIndex: 0, explanation: 'Massa dolorosa e flutuante em região vulvar posterior é característica de abscesso de glândula de Bartholin, tratado com marsupialização ou drenagem cirúrgica, associada a antibioticoterapia conforme o contexto. Antibioticoterapia oral isolada sem drenagem é insuficiente diante de coleção purulenta já organizada; excisão completa da glândula na fase aguda infecciosa aumenta o risco de complicações locais, sendo preferível na fase aguda a drenagem/marsupialização, reservando a excisão a casos recidivantes fora da fase aguda; observação isolada prolonga a dor e o risco de complicações; analgesia isolada não trata a coleção que exige drenagem.' },
  { id: 'ufsc_gerado26_048', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Adolescente, 16 anos, com menarca há 3 anos, ciclos irregulares, hirsutismo progressivo e acne importante. Assinale a dosagem a ser incluída na investigação laboratorial:', options: ['testosterona total e livre, para investigação de hiperandrogenismo.', 'apenas hemograma completo, sem qualquer avaliação hormonal.', 'apenas glicemia de jejum isolada, sem avaliação androgênica.', 'cálcio e fósforo séricos, sem qualquer relação com o quadro descrito.', 'apenas colesterol total, sem avaliação hormonal androgênica.'], correctIndex: 0, explanation: 'Hirsutismo progressivo e acne em adolescente com ciclos irregulares sugerem hiperandrogenismo, exigindo dosagem de testosterona total e livre. Hemograma isolado não avalia o eixo hormonal relevante; glicemia isolada não investiga a causa do hiperandrogenismo; cálcio e fósforo não têm relação direta com esse quadro; colesterol total isolado não substitui a avaliação hormonal androgênica.' },
  { id: 'ufsc_gerado26_049', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 26 anos, com dor pélvica súbita e intensa em fossa ilíaca direita, náuseas, ultrassonografia com Doppler evidenciando ausência de fluxo em ovário direito aumentado de volume, com cisto ovariano de 6cm. Assinale a conduta MAIS ADEQUADA:', options: ['exploração cirúrgica de urgência, dada a suspeita de torção anexial, buscando preservar o ovário quando viável.', 'observação clínica isolada por 24 horas, sem qualquer intervenção cirúrgica.', 'analgesia isolada e retorno ambulatorial em 7 dias, sem investigação de imagem adicional.', 'antibioticoterapia empírica isolada, considerando doença inflamatória pélvica como única hipótese.', 'ooforectomia bilateral profilática, independente da avaliação intraoperatória do ovário.'], correctIndex: 0, explanation: 'Dor pélvica súbita intensa com ausência de fluxo ao Doppler em ovário aumentado com cisto sugere torção anexial, emergência cirúrgica que exige exploração de urgência, buscando preservar o ovário quando ainda viável (destorção). Observação isolada por 24 horas arrisca necrose ovariana irreversível; analgesia isolada com retorno tardio também arrisca perda do órgão; antibioticoterapia isolada não trata a torção mecânica; ooforectomia bilateral profilática é desproporcional, devendo a viabilidade ser avaliada intraoperatoriamente antes de qualquer ressecção.' },
  { id: 'ufsc_gerado26_050', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Segundo as diretrizes brasileiras de rastreamento do câncer do colo do útero, assinale o método de rastreamento primário recomendado e o intervalo padrão:', options: ['citologia oncótica, com intervalo trienal após dois exames anuais consecutivos normais, a partir dos 25 anos.', 'ressonância magnética pélvica anual, a partir dos 18 anos.', 'tomografia computadorizada de pelve, a cada 5 anos, a partir dos 30 anos.', 'dosagem sérica de CA-125, anualmente, a partir da menarca.', 'ultrassonografia transvaginal isolada, semestralmente, em qualquer idade.'], correctIndex: 0, explanation: 'O rastreamento citológico brasileiro recomenda início aos 25 anos, com periodicidade trienal após dois exames anuais consecutivos normais. Ressonância magnética não é o método de rastreamento primário recomendado; tomografia computadorizada também não é método de rastreio populacional; CA-125 não é marcador de rastreamento para câncer de colo uterino; ultrassonografia transvaginal isolada não substitui a citologia.' },
  { id: 'ufsc_gerado26_051', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 55 anos, com fadiga, prurido e ondas de calor, ciclos menstruais ausentes há 14 meses. Assinale a conduta MAIS ADEQUADA em relação à terapia hormonal da menopausa:', options: ['pode ser considerada, individualizando risco-benefício, preferencialmente iniciada próximo ao início dos sintomas.', 'é sempre contraindicada em qualquer mulher na menopausa, independente do risco cardiovascular basal.', 'deve ser iniciada rotineiramente em todas as mulheres menopausadas, independente de sintomas ou contraindicações.', 'não tem qualquer relação com o alívio de sintomas vasomotores da menopausa.', 'deve ser mantida indefinidamente, sem qualquer reavaliação periódica do risco-benefício.'], correctIndex: 0, explanation: 'A terapia hormonal da menopausa pode ser considerada, individualizando o risco-benefício, preferencialmente iniciada próximo ao início dos sintomas (janela de oportunidade). Não é sempre contraindicada, dependendo do perfil de risco individual; não deve ser iniciada rotineiramente em todas as mulheres sem avaliação individualizada; tem relação direta com o alívio dos sintomas vasomotores, sendo essa uma de suas principais indicações; deve ser reavaliada periodicamente, não mantida indefinidamente sem reavaliação.' },
  { id: 'ufsc_gerado26_052', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Menino de 14 meses, ao exame de rotina, apresenta bolsa escrotal direita vazia, testículo direito palpável no canal inguinal, não descendo à manobra de tração para a bolsa escrotal. Assinale a conduta MAIS ADEQUADA:', options: ['encaminhamento para orquidopexia cirúrgica, idealmente entre 6 e 18 meses de idade, pelo risco de comprometimento da fertilidade e maior risco de malignização com o atraso.', 'observação isolada até os 10 anos de idade, aguardando descida espontânea, independente da persistência do quadro.', 'tratamento hormonal isolado com hCG como primeira linha, sem consideração de cirurgia em nenhum momento.', 'orquiectomia do testículo não descido como conduta padrão em toda criptorquidia unilateral.', 'nenhuma conduta específica, já que a criptorquidia unilateral não tem qualquer relação com fertilidade futura.'], correctIndex: 0, explanation: 'Criptorquidia persistente após o primeiro ano de vida tem indicação de orquidopexia cirúrgica, idealmente entre 6 e 18 meses, pelo risco de comprometimento da espermatogênese e maior risco de malignização testicular com o atraso do tratamento. Observação isolada até os 10 anos atrasa perigosamente a correção, prejudicando a fertilidade futura; tratamento hormonal isolado com hCG tem eficácia limitada e não é a primeira linha atual; orquiectomia não é a conduta padrão para testículo criptorquídico viável, sendo reservada a achados de atrofia ou lesão identificados no intraoperatório; a criptorquidia tem sim relação com risco de infertilidade e malignização, não sendo condição sem repercussão.' },
  { id: 'ufsc_gerado26_053', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Criança, 4 anos, com febre alta, exantema petequial que evolui rapidamente para lesões purpúricas em extremidades, hipotensão e rebaixamento do nível de consciência, líquor com predomínio de neutrófilos. Assinale a principal complicação endócrina aguda a ser monitorada nesse quadro:', options: ['insuficiência adrenal aguda por hemorragia das suprarrenais (síndrome de Waterhouse-Friderichsen).', 'hipertireoidismo agudo por tireoidite infecciosa.', 'diabetes insípido central permanente em todos os casos.', 'síndrome de secreção inadequada de hormônio antidiurético como achado obrigatório e universal.', 'hipoparatireoidismo permanente como complicação característica e esperada.'], correctIndex: 0, explanation: 'O quadro é compatível com meningococcemia fulminante, cuja complicação endócrina clássica é a insuficiência adrenal aguda por hemorragia das suprarrenais, conhecida como síndrome de Waterhouse-Friderichsen. Hipertireoidismo agudo por tireoidite infecciosa não é a complicação endócrina característica dessa condição; diabetes insípido central não é achado obrigatório em todos os casos; a síndrome de secreção inadequada de hormônio antidiurético pode ocorrer em contextos de infecção do sistema nervoso central, mas não é a complicação endócrina clássica e mais temida associada a esse quadro específico; hipoparatireoidismo permanente não é complicação característica da meningococcemia.' },
  { id: 'ufsc_gerado26_054', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Recém-nascido a termo, com atraso na eliminação de mecônio além de 48 horas de vida, distensão abdominal progressiva e episódios de vômitos, biópsia retal por sucção evidenciando ausência de células ganglionares na submucosa. Assinale o diagnóstico e a conduta definitiva:', options: ['doença de Hirschsprung; ressecção cirúrgica do segmento agangliônico, com abaixamento do intestino normalmente inervado.', 'tampão meconial isolado; apenas estímulo retal manual, sem necessidade de qualquer cirurgia.', 'atresia anal; colostomia definitiva permanente, sem qualquer procedimento de reconstrução posterior.', 'megacólon adquirido por constipação funcional; apenas laxante osmótico, sem necessidade de biópsia ou cirurgia.', 'íleo meconial isolado; apenas enema com contraste hidrossolúvel, sem necessidade de investigação histológica.'], correctIndex: 0, explanation: 'Atraso na eliminação de mecônio, distensão progressiva e ausência de células ganglionares na biópsia retal confirmam a doença de Hirschsprung, tratada definitivamente com ressecção do segmento agangliônico e abaixamento do intestino normalmente inervado. O tampão meconial isolado resolve-se geralmente com estímulo/enema simples, sem o achado histológico de agangliose; a atresia anal tem apresentação anatômica distinta (ausência de orifício anal) e a colostomia costuma ser temporária, seguida de reconstrução; a constipação funcional não cursa com esse achado histológico de ausência de células ganglionares; o íleo meconial relaciona-se tipicamente à fibrose cística e não apresenta agangliose à biópsia retal.' },
  { id: 'ufsc_gerado26_055', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Criança, 6 anos, com enurese noturna isolada e exame físico normal. Assinale a conduta inicial:', options: ['orientação comportamental e reasseguramento.', 'desmopressina imediata sem orientação comportamental prévia.', 'investigação urológica invasiva imediata.', 'restrição hídrica extrema durante todo o dia.', 'encaminhamento imediato para cirurgia urológica, sem qualquer abordagem clínica prévia.'], correctIndex: 0, explanation: 'Enurese isolada sem sinais de alarme é tratada inicialmente com orientação comportamental. Desmopressina imediata sem tentativa comportamental prévia pula uma etapa terapêutica de primeira linha; investigação urológica invasiva não é indicada; restrição hídrica extrema é inadequada; cirurgia não é indicada para esse quadro funcional isolado.' },
  { id: 'ufsc_gerado26_056', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Menino de 6 anos, com tosse seca, sibilância expiratória difusa e uso de musculatura acessória, falando apenas frases curtas, saturação de oxigênio de 91% em ar ambiente. Assinale a classificação de gravidade da crise asmática e a conduta inicial:', options: ['crise moderada a grave; broncodilatador de curta duração inalatório repetido e corticoide sistêmico precoce, com oxigenoterapia conforme saturação.', 'crise leve; apenas observação domiciliar, sem necessidade de broncodilatador ou corticoide.', 'crise muito grave com iminência de parada respiratória; apenas corticoide oral isolado, sem broncodilatador.', 'crise leve a moderada; antibioticoterapia empírica como conduta prioritária, sem broncodilatador.', 'exacerbação infecciosa isolada; apenas antitérmico, sem qualquer broncodilatador ou corticoide.'], correctIndex: 0, explanation: 'Uso de musculatura acessória, fala entrecortada em frases curtas e saturação reduzida caracterizam crise asmática moderada a grave, tratada com broncodilatador de curta duração repetido, corticoide sistêmico precoce e oxigenoterapia conforme a saturação. Classificar como crise leve subestima a gravidade e atrasa o tratamento adequado; crise muito grave com iminência de parada exigiria suporte ventilatório mais agressivo, não apenas corticoide oral isolado sem broncodilatador; antibioticoterapia empírica não é a conduta prioritária na crise asmática, que não é primariamente infecciosa; antitérmico isolado não trata a obstrução das vias aéreas presente na crise.' },
  { id: 'ufsc_gerado26_057', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Recém-nascido, filho de mãe HIV positivo com carga viral detectável no terceiro trimestre, apesar de terapia antirretroviral. Assinale a conduta em relação à profilaxia neonatal e ao aleitamento:', options: ['profilaxia antirretroviral neonatal reforçada, conforme risco estimado, e contraindicação absoluta ao aleitamento materno.', 'nenhuma profilaxia neonatal, dado que a mãe já está em terapia antirretroviral.', 'aleitamento materno liberado, desde que a mãe continue em terapia antirretroviral.', 'profilaxia neonatal apenas se o recém-nascido apresentar sintomas, não de forma preventiva.', 'suspensão da terapia antirretroviral materna no puerpério, sem qualquer relação com o aleitamento.'], correctIndex: 0, explanation: 'Carga viral detectável no terceiro trimestre, mesmo em terapia, aumenta o risco de transmissão vertical, justificando profilaxia antirretroviral neonatal reforçada e mantendo a contraindicação absoluta ao aleitamento materno no Brasil. Não administrar profilaxia neonatal ignora o risco residual de transmissão; o aleitamento materno é contraindicado em mães HIV positivo no Brasil, independente do uso de terapia antirretroviral; a profilaxia deve ser preventiva, não reservada apenas a sintomas já estabelecidos; a terapia antirretroviral materna não deve ser suspensa no puerpério, sendo mantida pela saúde materna.' },
  { id: 'ufsc_gerado26_058', banca: 'UFSC', cycle: 'Internato', subject: 'Neonatologia', text: 'Recém-nascido, 28 semanas, peso de 950g, com desconforto respiratório progressivo desde os primeiros minutos de vida, radiografia de tórax com infiltrado reticulogranular difuso. Assinale a conduta recomendada:', options: ['suporte ventilatório (CPAP nasal ou ventilação mecânica conforme gravidade) e surfactante exógeno, se indicado.', 'antibioticoterapia isolada, sem qualquer suporte ventilatório.', 'observação isolada, sem qualquer intervenção respiratória.', 'apenas oxigênio em cateter nasal de baixo fluxo, independente da gravidade do desconforto.', 'ventilação mecânica invasiva obrigatória em todos os casos, sem considerar CPAP nasal.'], correctIndex: 0, explanation: 'O quadro é compatível com síndrome do desconforto respiratório do recém-nascido pré-termo por deficiência de surfactante, tratado com suporte ventilatório adequado e surfactante exógeno quando indicado. Antibioticoterapia isolada não trata a causa primária; observação isolada é perigosa; oxigênio em baixo fluxo isolado pode ser insuficiente; ventilação mecânica invasiva obrigatória em todos os casos ignora a possibilidade de suporte não invasivo em casos menos graves.' },
  { id: 'ufsc_gerado26_059', banca: 'UFSC', cycle: 'Internato', subject: 'Neonatologia', text: 'Recém-nascido a termo, Apgar 3 no primeiro minuto, apneia e frequência cardíaca de 75bpm após os passos iniciais de reanimação neonatal. Assinale a conduta imediata:', options: ['ventilação com pressão positiva, reavaliando a frequência cardíaca após 30 segundos.', 'apenas estimulação tátil adicional, sem qualquer suporte ventilatório.', 'compressões torácicas isoladas, sem qualquer suporte ventilatório associado.', 'administração isolada de adrenalina, sem qualquer ventilação prévia.', 'observação clínica isolada por 5 minutos, sem qualquer intervenção.'], correctIndex: 0, explanation: 'Após os passos iniciais, apneia e frequência cardíaca abaixo de 100bpm indicam ventilação com pressão positiva, reavaliando a resposta em 30 segundos. Estimulação tátil isolada é insuficiente; compressões torácicas isoladas sem ventilação associada não seguem o algoritmo padrão; adrenalina é reservada a casos refratários; observar sem intervir é perigoso diante desse quadro de asfixia neonatal.' },
  { id: 'ufsc_gerado26_060', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem, 38 anos, trabalhador em limpeza de áreas alagadas após enchente, apresenta febre alta, mialgia intensa em panturrilhas, hiperemia conjuntival bilateral sem secreção, icterícia progressiva e oligúria. Creatinina 3,8mg/dL; bilirrubina total 12mg/dL às custas de direta. Assinale o diagnóstico MAIS PROVÁVEL e o tratamento:', options: ['leptospirose (forma íctero-hemorrágica, síndrome de Weil); penicilina cristalina ou ceftriaxona intravenosa, associada a suporte clínico.', 'hepatite A aguda; apenas suporte clínico, sem necessidade de antibioticoterapia.', 'malária por Plasmodium falciparum; artesunato intravenoso, independente da história epidemiológica de enchente.', 'febre amarela; vacinação imediata como tratamento da doença já instalada.', 'colangite aguda; apenas antibioticoterapia oral ambulatorial, sem necessidade de internação.'], correctIndex: 0, explanation: 'Mialgia intensa em panturrilhas, hiperemia conjuntival sem secreção, icterícia e insuficiência renal após exposição a água de enchente são o quadro clássico da leptospirose na forma íctero-hemorrágica (síndrome de Weil), tratada com penicilina cristalina ou ceftriaxona intravenosa e suporte clínico. A hepatite A não explica a insuficiência renal nem a mialgia intensa característica; a malária não é a hipótese mais provável dado o contexto epidemiológico de exposição a água de enchente, mais típico de leptospirose; a vacinação não trata a febre amarela já instalada, além de o quadro não ser típico dessa doença; a colangite aguda não explica a mialgia intensa nem a hiperemia conjuntival descritas.' },
  { id: 'ufsc_gerado26_061', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Adolescente de 15 anos, colega de classe de um caso confirmado de doença meningocócica há 24 horas, com contato próximo e prolongado em sala de aula, assintomático. Assinale a conduta MAIS ADEQUADA em relação à quimioprofilaxia:', options: ['rifampicina por via oral, idealmente iniciada em até 48 horas do contato com o caso índice.', 'nenhuma profilaxia é necessária, pois o adolescente está assintomático no momento da avaliação.', 'vacinação isolada contra meningococo, sem necessidade de quimioprofilaxia antibiótica.', 'antibioticoterapia intravenosa hospitalar, independente da ausência de sintomas.', 'observação clínica por 30 dias, sem qualquer profilaxia medicamentosa.'], correctIndex: 0, explanation: 'Contactantes próximos de caso confirmado de doença meningocócica devem receber quimioprofilaxia com rifampicina oral, idealmente em até 48 horas do contato, mesmo estando assintomáticos. Não profilaxiar ignora o risco de transmissão a contactantes próximos; a vacinação isolada não substitui a quimioprofilaxia antibiótica para contactantes recentes, pois não confere proteção imediata; antibioticoterapia intravenosa hospitalar é desproporcional para profilaxia em contactante assintomático; observação sem profilaxia por 30 dias expõe o contactante ao risco de desenvolver a doença sem proteção.' },
  { id: 'ufsc_gerado26_062', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Infectologia', text: 'Homem, 34 anos, HIV positivo, CD4 de 60 células/mm³, com cefaleia progressiva de piora insidiosa, febre baixa e rigidez de nuca discreta, líquor com pressão de abertura elevada, poucas células, proteína pouco alterada e tinta da China positiva. Assinale o tratamento de indução MAIS APROPRIADO:', options: ['anfotericina B associada a flucitosina, seguida de fluconazol de manutenção.', 'sulfadiazina associada a pirimetamina e ácido folínico, sem qualquer antifúngico.', 'ceftriaxona isolada, sem qualquer cobertura antifúngica.', 'aciclovir intravenoso isolado, sem qualquer antifúngico.', 'tuberculostáticos em esquema RIPE, sem qualquer antifúngico.'], correctIndex: 0, explanation: 'Cefaleia progressiva, pressão liquórica elevada e tinta da China positiva em paciente com CD4 muito baixo confirmam meningite criptocócica, tratada na fase de indução com anfotericina B associada a flucitosina, seguida de fluconazol de manutenção. Sulfadiazina, pirimetamina e ácido folínico tratam neurotoxoplasmose, não meningite fúngica; ceftriaxona isolada cobre bactérias, não fungos; aciclovir é antiviral, sem ação sobre Cryptococcus; RIPE trata tuberculose, não explicando o achado de tinta da China positiva característico de infecção fúngica.' },
  { id: 'ufsc_gerado26_063', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Homem, 58 anos, hipertenso mal controlado, com dor torácica súbita, intensa, de caráter lancinante, irradiada para o dorso interescapular, assimetria de pulsos entre os membros superiores, radiografia de tórax com alargamento do mediastino. Assinale o diagnóstico MAIS PROVÁVEL e a conduta:', options: ['dissecção aórtica tipo A (Stanford); cirurgia de urgência, com controle rigoroso da pressão arterial e frequência cardíaca até a intervenção.', 'infarto agudo do miocárdio de parede inferior; trombólise imediata, independente de outros achados clínicos.', 'pericardite aguda; anti-inflamatório não esteroidal isolado, sem necessidade de imagem adicional.', 'embolia pulmonar maciça; trombolítico isolado, sem investigação de imagem torácica adicional.', 'espasmo esofágico difuso; apenas antiespasmódico, sem necessidade de investigação cardiovascular.'], correctIndex: 0, explanation: 'Dor lancinante irradiada para o dorso, assimetria de pulsos e alargamento de mediastino são achados clássicos da dissecção aórtica tipo A, exigindo cirurgia de urgência e controle rigoroso da pressão e frequência cardíaca até a intervenção. Trombolisar um infarto sem excluir dissecção aórtica é extremamente perigoso, podendo agravar a dissecção com sangramento; a pericardite aguda não explica a assimetria de pulsos nem o alargamento mediastinal; a embolia pulmonar não explica a assimetria de pulsos nem a dor com essas características irradiadas para o dorso; o espasmo esofágico não explica os achados de imagem e o exame físico vascular descritos.' },
  { id: 'ufsc_gerado26_064', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Cardiologia', text: 'Homem, 45 anos, usuário de drogas injetáveis, com febre prolongada, sopro cardíaco novo de regurgitação, lesões de Janeway em palmas e nódulos de Osler dolorosos em polpas digitais, hemoculturas seriadas positivas para Staphylococcus aureus. Assinale o diagnóstico e o exame complementar mais indicado para avaliação de vegetações valvares:', options: ['endocardite infecciosa; ecocardiograma (transtorácico e, se necessário, transesofágico) para avaliação de vegetações.', 'febre reumática aguda; ecocardiograma não tem qualquer papel na investigação desse quadro.', 'miocardite viral; ressonância cardíaca como único exame necessário, sem ecocardiograma.', 'pericardite purulenta isolada; tomografia de tórax como exame de escolha, sem ecocardiograma.', 'síndrome antifosfolípide; anticorpos antifosfolípides como único exame necessário, sem avaliação cardíaca estrutural.'], correctIndex: 0, explanation: 'Febre prolongada, sopro novo, lesões de Janeway, nódulos de Osler e hemoculturas positivas preenchem critérios para endocardite infecciosa, cuja avaliação de vegetações valvares é feita por ecocardiograma transtorácico e, se necessário, transesofágico. Febre reumática aguda não explica as lesões periféricas descritas nem as hemoculturas positivas; miocardite viral não explica o sopro de regurgitação novo nem as lesões periféricas; pericardite purulenta não é a hipótese mais compatível com esse conjunto de achados; a síndrome antifosfolípide não explica a febre prolongada com hemoculturas positivas, sendo diagnóstico distinto.' },
  { id: 'ufsc_gerado26_065', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Homem, 45 anos, com aumento progressivo de mãos, pés e traços faciais nos últimos anos, prognatismo, diastema dentário, cefaleia e sudorese excessiva. Assinale o exame MAIS ADEQUADO para confirmação diagnóstica, após a triagem inicial:', options: ['teste de supressão do hormônio do crescimento com sobrecarga oral de glicose.', 'dosagem isolada de TSH, sem qualquer relação com a hipótese diagnóstica.', 'teste de estímulo com hipoglicemia insulínica para avaliação do eixo tireotrófico.', 'dosagem isolada de prolactina como único exame confirmatório necessário.', 'curva glicêmica de 2 horas isolada, sem dosagem de IGF-1 ou GH.'], correctIndex: 0, explanation: 'O quadro clínico sugere acromegalia, confirmada, após triagem com IGF-1 elevado, pelo teste de supressão do GH com sobrecarga oral de glicose, que normalmente suprime o GH e não o faz em pacientes com excesso autônomo desse hormônio. Dosagem isolada de TSH não tem relação com essa hipótese diagnóstica de excesso de GH; o teste de estímulo com hipoglicemia insulínica avalia o eixo corticotrófico/somatotrófico em contexto de suspeita de insuficiência, não de excesso hormonal; a dosagem isolada de prolactina não confirma acromegalia, podendo estar elevada por outros motivos (como compressão da haste hipofisária), mas não é o exame confirmatório dessa condição; a curva glicêmica isolada sem os marcadores hormonais específicos (IGF-1, GH) não confirma o diagnóstico.' },
  { id: 'ufsc_gerado26_066', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Endocrinologia', text: 'Homem, 50 anos, obeso, com poliúria, polidipsia, glicemia de jejum de 190mg/dL em duas ocasiões. Assinale a alternativa CORRETA sobre o diagnóstico de diabetes mellitus tipo 2:', options: ['pode ser confirmado por glicemia de jejum igual ou superior a 126mg/dL em duas ocasiões distintas.', 'exige obrigatoriamente teste oral de tolerância à glicose para confirmação diagnóstica em todos os casos.', 'só pode ser diagnosticado na presença de cetoacidose diabética associada.', 'depende exclusivamente da presença de anticorpos anti-ilhota positivos.', 'exige glicemia de jejum superior a 300mg/dL para confirmação diagnóstica.'], correctIndex: 0, explanation: 'O diagnóstico pode ser confirmado por glicemia de jejum igual ou superior a 126mg/dL em duas ocasiões distintas. O TOTG não é obrigatório em todos os casos; a cetoacidose não é pré-requisito diagnóstico do tipo 2; anticorpos anti-ilhota são marcadores de diabetes tipo 1; não há exigência de glicemia acima de 300mg/dL.' },
  { id: 'ufsc_gerado26_067', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Homem, 32 anos, com lesões vesiculobolhosas extremamente pruriginosas, agrupadas, em superfícies extensoras de cotovelos e nádegas, associadas a diarreia crônica e distensão abdominal. Assinale o diagnóstico MAIS PROVÁVEL e a doença sistêmica associada:', options: ['dermatite herpetiforme; doença celíaca.', 'penfigoide bolhoso; diabetes mellitus tipo 2.', 'pênfigo vulgar; timoma.', 'psoríase pustulosa; artrite psoriásica isolada, sem relação intestinal.', 'urticária crônica; hipotireoidismo autoimune isolado.'], correctIndex: 0, explanation: 'Lesões vesiculobolhosas extremamente pruriginosas em superfícies extensoras, associadas a sintomas intestinais crônicos, são características da dermatite herpetiforme, fortemente associada à doença celíaca subjacente, tratada com dieta isenta de glúten e, se necessário, dapsona. O penfigoide bolhoso acomete predominantemente idosos com bolhas tensas, sem essa associação intestinal; o pênfigo vulgar cursa com bolhas flácidas e acometimento de mucosas, sem essa associação com doença celíaca; a psoríase pustulosa não cursa com esse padrão vesiculobolhoso pruriginoso nem com diarreia crônica associada; a urticária crônica não cursa com lesões vesiculobolhosas nem com esses sintomas intestinais.' },
  { id: 'ufsc_gerado26_068', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Dermatologia', text: 'Mulher, 50 anos, nota lesão pigmentada em perna com bordas irregulares, coloração heterogênea (marrom, preto e áreas avermelhadas), diâmetro de 8mm e crescimento assimétrico progressivo nos últimos 3 meses. Assinale a conduta MAIS ADEQUADA:', options: ['biópsia excisional da lesão com margem estreita, para diagnóstico histológico e definição do índice de Breslow.', 'crioterapia empírica da lesão pigmentada, sem qualquer biópsia prévia.', 'observação clínica isolada por 12 meses, sem qualquer biópsia, dada a ausência de sintomas.', 'shaving (biópsia tangencial) como método preferido para lesão pigmentada suspeita.', 'laserterapia estética da lesão, sem qualquer investigação histológica prévia.'], correctIndex: 0, explanation: 'Lesão pigmentada com critérios de assimetria, bordas irregulares, coloração heterogênea e crescimento progressivo (critérios ABCDE) é suspeita para melanoma, exigindo biópsia excisional com margem estreita para diagnóstico e definição do índice de Breslow, que orienta o estadiamento e a conduta. Crioterapia empírica sem biópsia trataria inadequadamente uma possível lesão maligna sem diagnóstico; observação por 12 meses atrasa perigosamente o diagnóstico diante de critérios clínicos suspeitos; o shaving é contraindicado em lesões pigmentadas suspeitas de melanoma, pois compromete a avaliação correta da espessura tumoral (Breslow); laserterapia estética também trataria inadequadamente uma lesão potencialmente maligna sem diagnóstico histológico prévio.' },
  { id: 'ufsc_gerado26_069', banca: 'UFSC', cycle: 'Internato', subject: 'Urologia', text: 'Homem, 38 anos, com dor lombar em cólica de forte intensidade, irradiada para a região inguinal, náuseas e agitação, sem febre, exame de urina com hematúria microscópica. Assinale o exame de imagem MAIS ADEQUADO para investigação inicial e a conduta analgésica preferencial:', options: ['tomografia computadorizada de abdome sem contraste; anti-inflamatório não esteroidal como analgesia de primeira linha, na ausência de contraindicações.', 'ressonância magnética de abdome com contraste, como exame de escolha em todos os casos.', 'urografia excretora como exame de primeira linha atual, preterindo a tomografia.', 'ultrassonografia isolada como único exame necessário, sem necessidade de tomografia em nenhum caso.', 'opioide intravenoso como única opção analgésica válida, com anti-inflamatório contraindicado em qualquer cólica renal.'], correctIndex: 0, explanation: 'A cólica renal por provável nefrolitíase é investigada preferencialmente por tomografia de abdome sem contraste, exame de escolha atual para detecção de cálculos, e tratada com anti-inflamatório não esteroidal como analgesia de primeira linha, na ausência de contraindicações. Ressonância com contraste não é o exame de escolha nem necessária em todos os casos; a urografia excretora foi amplamente substituída pela tomografia sem contraste na prática atual; a ultrassonografia tem menor sensibilidade para cálculos ureterais em comparação à tomografia, sendo alternativa em situações específicas (gestantes, por exemplo), não substituto universal; o anti-inflamatório não é contraindicado de forma geral na cólica renal, sendo inclusive preferido como analgesia inicial.' },
  { id: 'ufsc_gerado26_070', banca: 'UFSC', cycle: 'Internato', subject: 'Urologia', text: 'Adolescente de 16 anos, ao exame de rotina, apresenta dilatação de veias no escroto esquerdo, com aspecto de "saco de vermes" à palpação, mais evidente em posição ortostática e que reduz em decúbito, associada a discreta hipotrofia do testículo ipsilateral em relação ao contralateral. Assinale a conduta MAIS ADEQUADA:', options: ['correção cirúrgica (varicocelectomia), dada a hipotrofia testicular associada, com objetivo de preservar a fertilidade futura.', 'observação isolada até a idade adulta, independente da hipotrofia testicular já identificada.', 'apenas uso de suspensório escrotal, sem qualquer indicação cirúrgica em nenhuma circunstância.', 'orquiectomia do testículo hipotrófico, como conduta padrão para essa condição.', 'antibioticoterapia empírica isolada, considerando epididimite como única hipótese diagnóstica.'], correctIndex: 0, explanation: 'Varicocele com hipotrofia testicular ipsilateral em adolescente tem indicação de correção cirúrgica, visando preservar a fertilidade futura, já que a varicocele é causa reconhecida de comprometimento da espermatogênese. Observação isolada até a idade adulta, com hipotrofia já identificada, pode comprometer ainda mais a função testicular; suspensório escrotal isolado não corrige a causa nem reverte a hipotrofia associada; orquiectomia é conduta desproporcional para uma condição tratável com preservação do órgão; antibioticoterapia não é indicada, pois o quadro descrito (veias dilatadas, aspecto de "saco de vermes", redução em decúbito) não é compatível com processo infeccioso agudo como epididimite.' },
  { id: 'ufsc_gerado26_071', banca: 'UFSC', cycle: 'Internato', subject: 'Urgência e Emergência', text: 'Mulher, 28 anos, minutos após receber injeção intramuscular de penicilina, desenvolve urticária generalizada, edema de lábios e língua, estridor laríngeo e hipotensão (PA 78/45mmHg). Assinale a conduta imediata prioritária:', options: ['adrenalina intramuscular na face anterolateral da coxa, repetida conforme necessário, associada a suporte de via aérea e reposição volêmica.', 'anti-histamínico intravenoso isolado como primeira e única medida terapêutica.', 'corticoide intravenoso isolado, sem administração de adrenalina.', 'observação clínica por 30 minutos antes de qualquer medicação, para confirmar a gravidade do quadro.', 'apenas broncodilatador inalatório isolado, sem adrenalina ou suporte de via aérea.'], correctIndex: 0, explanation: 'Anafilaxia com comprometimento de via aérea e hipotensão exige adrenalina intramuscular imediata na coxa, repetida conforme necessário, associada a suporte de via aérea e reposição volêmica. Anti-histamínico isolado tem ação mais lenta e não reverte a hipotensão nem o edema de via aérea com a mesma eficácia da adrenalina; corticoide isolado tem início de ação lento, não sendo a primeira medida em uma emergência com comprometimento de via aérea; observar por 30 minutos antes de medicar é extremamente perigoso diante de sinais de gravidade já presentes; broncodilatador isolado não trata o edema de via aérea superior nem a hipotensão sistêmica.' },
  { id: 'ufsc_gerado26_072', banca: 'UFSC', cycle: 'Internato', subject: 'Urgência e Emergência', text: 'Homem, 30 anos, resgatado após submersão em água doce por cerca de 3 minutos, consciente na chegada ao pronto-socorro, com tosse e discreto desconforto respiratório, saturação de oxigênio de 94% em ar ambiente. Assinale a conduta MAIS ADEQUADA:', options: ['observação hospitalar por período mínimo de 4 a 6 horas, mesmo com sintomas iniciais leves, pelo risco de deterioração respiratória tardia.', 'alta hospitalar imediata, dado que o paciente está consciente e sem desconforto respiratório importante no momento da avaliação inicial.', 'antibioticoterapia profilática de rotina para todo episódio de quase afogamento, independente de sinais de infecção.', 'ventilação mecânica invasiva imediata em todos os casos de quase afogamento, independente da saturação de oxigênio.', 'indução de vômito como medida terapêutica para eliminar a água aspirada.'], correctIndex: 0, explanation: 'Mesmo com sintomas iniciais leves, todo episódio de quase afogamento com sintomas respiratórios exige observação hospitalar por algumas horas, pelo risco de deterioração respiratória tardia (edema pulmonar). Alta imediata ignora esse risco de piora tardia; antibioticoterapia profilática de rotina não é recomendada na ausência de sinais de infecção; ventilação mecânica invasiva não é indicada rotineiramente em todo caso, dependendo da gravidade respiratória; induzir vômito não é conduta recomendada e pode aumentar o risco de aspiração.' },
  { id: 'ufsc_gerado26_073', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Vascular', text: 'Homem, 45 anos, com edema unilateral de membro inferior esquerdo, dor à palpação da panturrilha e sinal de Homans positivo, sem antecedente de trauma. Assinale a hipótese diagnóstica MAIS PROVÁVEL e a conduta:', options: ['trombose venosa profunda; anticoagulação, conforme confirmação por ultrassonografia com Doppler.', 'celulite isolada; apenas antibioticoterapia, sem investigação de trombose venosa.', 'linfedema primário; compressão elástica isolada, sem qualquer investigação de trombose.', 'ruptura de cisto de Baker; observação clínica isolada, sem investigação vascular.', 'insuficiência arterial aguda; heparina isolada, sem investigação de causa venosa.'], correctIndex: 0, explanation: 'Edema unilateral com dor à palpação da panturrilha e sinal de Homans positivo sugerem trombose venosa profunda, confirmada por ultrassonografia com Doppler e tratada com anticoagulação. Celulite isolada não explica adequadamente esse conjunto de achados sem investigar a possibilidade de trombose concomitante; linfedema primário teria evolução mais crônica e progressiva, não aguda dessa forma; ruptura de cisto de Baker é diagnóstico diferencial relevante, mas não deve ser assumida sem excluir trombose venosa profunda por imagem; insuficiência arterial aguda cursaria com dor isquêmica, palidez e ausência de pulsos, não esse quadro de edema com sinal de Homans.' },
  { id: 'ufsc_gerado26_074', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Pneumologia', text: 'Homem, 30 anos, longilíneo, com dor torácica súbita e dispneia, ausculta com murmúrio vesicular abolido em hemitórax direito, radiografia com pequeno pneumotórax, sem desvio de mediastino. Assinale a conduta MAIS ADEQUADA:', options: ['observação clínica com oxigenoterapia suplementar.', 'drenagem torácica em selo d\'água obrigatória, independente do volume.', 'toracotomia de urgência, independente da estabilidade clínica.', 'pleurodese química imediata no primeiro episódio.', 'ventilação mecânica invasiva imediata, independente da saturação de oxigênio.'], correctIndex: 0, explanation: 'Pneumotórax de pequeno volume em paciente estável pode ser conduzido com observação e oxigenoterapia suplementar. Drenagem obrigatória em todos os casos ignora a possibilidade de manejo conservador; toracotomia de urgência é desproporcional; pleurodese não é indicada no primeiro episódio de pequeno volume; ventilação mecânica invasiva não é indicada rotineiramente nesse cenário.' },
  { id: 'ufsc_gerado26_075', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Neurologia', text: 'Homem, 68 anos, apresenta há 30 minutos fraqueza súbita em dimídio direito e dificuldade para articular palavras, sem história de trauma, glicemia capilar 110mg/dL, tomografia de crânio sem contraste sem sinais de sangramento. Assinale o principal critério de tempo a ser considerado para elegibilidade à trombólise intravenosa:', options: ['início dos sintomas dentro de uma janela de até 4,5 horas, na ausência de contraindicações.', 'início dos sintomas dentro de uma janela de até 24 horas, independente de qualquer outro critério.', 'ausência de qualquer limite de tempo para a trombólise intravenosa, desde que a tomografia inicial seja normal.', 'necessidade de aguardar ressonância magnética completa antes de definir qualquer janela terapêutica.', 'janela de apenas 30 minutos desde o início dos sintomas, sem qualquer flexibilidade adicional.'], correctIndex: 0, explanation: 'A trombólise intravenosa no AVC isquêmico agudo é elegível dentro de uma janela de até 4,5 horas do início dos sintomas, na ausência de contraindicações, sendo o tempo um dos critérios centrais dessa decisão. Uma janela de 24 horas não corresponde ao critério padrão para trombólise intravenosa (podendo se aplicar a critérios distintos de trombectomia mecânica em casos selecionados); não há ausência de limite de tempo, sendo esse um critério central e não dispensável; aguardar ressonância completa pode atrasar desnecessariamente uma decisão tempo-dependente; a janela de elegibilidade não se limita a apenas 30 minutos, sendo mais ampla conforme protocolos vigentes.' },
  { id: 'ufsc_gerado26_076', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Nefrologia', text: 'Homem, 45 anos, com edema periorbitário e de membros inferiores, proteinúria de 5g/24h, hipoalbuminemia e hiperlipidemia, sem hematúria significativa. Assinale o diagnóstico sindrômico e a principal complicação trombótica associada:', options: ['síndrome nefrótica; trombose de veia renal.', 'síndrome nefrítica; glomerulonefrite rapidamente progressiva.', 'insuficiência renal aguda pré-renal; necrose tubular aguda.', 'síndrome hemolítico-urêmica; trombocitopenia isolada.', 'nefrite intersticial aguda; eosinofilúria isolada.'], correctIndex: 0, explanation: 'Proteinúria maciça, hipoalbuminemia, edema e hiperlipidemia caracterizam a síndrome nefrótica, cuja complicação trombótica clássica é a trombose de veia renal. A síndrome nefrítica cursa com hematúria e hipertensão proeminentes; a insuficiência renal aguda pré-renal não explica a proteinúria maciça; a síndrome hemolítico-urêmica cursa com anemia hemolítica microangiopática; a nefrite intersticial aguda cursa tipicamente com eosinofilúria.' },
  { id: 'ufsc_gerado26_077', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Gastroenterologia', text: 'Mulher, 30 anos, com diarreia crônica, distensão abdominal e anemia ferropriva, sorologia positiva para antitransglutaminase. Assinale o tratamento indicado:', options: ['dieta isenta de glúten.', 'corticoide isolado.', 'antibiótico de amplo espectro.', 'dieta isenta de lactose.', 'suplementação isolada de ferro, sem qualquer restrição alimentar.'], correctIndex: 0, explanation: 'Anticorpos antitransglutaminase positivos confirmam doença celíaca, tratada com dieta isenta de glúten por toda a vida. Corticoide isolado não trata a causa autoimune; antibiótico não tem papel nessa enteropatia não infecciosa; dieta isenta de lactose trataria intolerância à lactose; suplementação de ferro isolada, sem retirar o glúten, não trata a causa da má absorção.' },
  { id: 'ufsc_gerado26_078', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Clínica Médica', text: 'Homem, 70 anos, com dispneia progressiva aos esforços, edema de membros inferiores, ecocardiograma evidenciando espessamento importante do miométrio ventricular com padrão granular "em vidro fosco" ao ultrassom, eletrocardiograma com baixa voltagem apesar da hipertrofia ecocardiográfica. Assinale o diagnóstico MAIS PROVÁVEL:', options: ['amiloidose cardíaca.', 'miocardiopatia hipertrófica sarcomérica isolada.', 'miocardite viral aguda.', 'pericardite constritiva isolada.', 'cardiopatia hipertensiva isolada, sem outra doença sistêmica associada.'], correctIndex: 0, explanation: 'A discrepância entre espessamento miocárdico importante ao ecocardiograma (com padrão granular "em vidro fosco") e baixa voltagem ao eletrocardiograma é achado característico da amiloidose cardíaca, causada pelo depósito de substância amiloide no miocárdio. A miocardiopatia hipertrófica sarcomérica isolada tipicamente cursa com alta voltagem ao ECG, compatível com a hipertrofia, não com essa discrepância; a miocardite viral aguda não explica esse padrão infiltrativo característico; a pericardite constritiva não explica o espessamento miocárdico com esse padrão granular específico; a cardiopatia hipertensiva isolada também cursaria com alta voltagem compatível com a hipertrofia, não com baixa voltagem discrepante.' },
  { id: 'ufsc_gerado26_079', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Clínica Cirúrgica', text: 'Homem, 50 anos, no terceiro dia de pós-operatório de cirurgia abdominal eletiva, apresenta febre de 38,7°C, taquicardia e drenagem de secreção purulenta pela ferida operatória, com bordas hiperemiadas. Assinale a conduta MAIS ADEQUADA:', options: ['abertura e drenagem da ferida operatória, com coleta de material para cultura e antibioticoterapia conforme a gravidade do quadro.', 'sutura de reforço da ferida, sem qualquer drenagem ou investigação microbiológica.', 'apenas curativo oclusivo, sem abertura da ferida ou antibioticoterapia.', 'reoperação com nova laparotomia ampla, independente da gravidade local da infecção de ferida.', 'observação isolada por 5 dias, sem qualquer intervenção sobre a ferida.'], correctIndex: 0, explanation: 'Infecção de sítio cirúrgico com secreção purulenta exige abertura e drenagem da ferida, com coleta de cultura e antibioticoterapia conforme a gravidade. Suturar a ferida infectada sem drenagem aprisionaria a infecção; apenas curativo oclusivo sem abertura não trata a coleção purulenta; reoperação com nova laparotomia ampla é desproporcional para uma infecção de ferida superficial/de parede, sem sinais de complicação intra-abdominal; observação isolada por 5 dias atrasa o tratamento de uma infecção já estabelecida.' },
  { id: 'ufsc_gerado26_080', banca: 'UFSC', cycle: 'Internato', subject: 'Medicina Intensiva', text: 'Paciente, 65 anos, no segundo dia pós-infarto agudo do miocárdio extenso de parede anterior, evolui com hipotensão persistente (PA 78/50mmHg), extremidades frias e má perfusão periférica, apesar de reposição volêmica criteriosa, com estertores pulmonares bilaterais. Assinale a conduta MAIS ADEQUADA:', options: ['suporte inotrópico/vasopressor conforme o perfil hemodinâmico, associado à consideração de suporte circulatório mecânico em casos refratários.', 'reposição volêmica agressiva adicional, independente dos estertores pulmonares já presentes.', 'apenas diurético de alça isolado, sem qualquer suporte inotrópico ou vasopressor.', 'betabloqueador em altas doses como conduta prioritária diante da hipotensão apresentada.', 'observação clínica isolada, sem qualquer intervenção hemodinâmica, aguardando resolução espontânea.'], correctIndex: 0, explanation: 'O quadro é compatível com choque cardiogênico pós-infarto extenso, exigindo suporte inotrópico/vasopressor conforme o perfil hemodinâmico, com consideração de suporte circulatório mecânico (como balão intra-aórtico) em casos refratários. Reposição volêmica agressiva adicional pode agravar a congestão pulmonar já presente; diurético isolado sem suporte inotrópico não corrige a hipoperfusão sistêmica; betabloqueador em altas doses é contraindicado nesse contexto de choque, podendo piorar ainda mais a função contrátil e a hipotensão; observação isolada é perigosa diante de um choque cardiogênico estabelecido.' },
  { id: 'ufsc_gerado26_081', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Hematologia', text: 'Homem, 68 anos, assintomático, achado incidental de linfocitose persistente (leucócitos 42.000/mm³, com 80% de linfócitos pequenos e maduros) em hemograma de rotina, esfregaço periférico evidenciando numerosas manchas de Gumprecht (smudge cells). Assinale o diagnóstico MAIS PROVÁVEL e a conduta inicial mais apropriada:', options: ['leucemia linfocítica crônica; observação clínica (\"watch and wait\") em pacientes assintomáticos e sem critérios de tratamento.', 'leucemia mieloide crônica; inibidor de tirosina-quinase imediato, independente de sintomas.', 'mononucleose infecciosa aguda; apenas suporte clínico por 2 semanas, sem necessidade de investigação adicional.', 'linfoma de Burkitt; quimioterapia de urgência, independente da ausência de sintomas.', 'reação leucemoide por infecção bacteriana oculta; antibioticoterapia empírica isolada, sem investigação hematológica.'], correctIndex: 0, explanation: 'Linfocitose persistente com linfócitos pequenos maduros e manchas de Gumprecht ao esfregaço são achados clássicos da leucemia linfocítica crônica, frequentemente conduzida com observação clínica (\"watch and wait\") em pacientes assintomáticos, sem critérios de tratamento imediato. A leucemia mieloide crônica cursa com leucocitose com desvio à esquerda de toda a série granulocítica, não linfocitose de células maduras; a mononucleose cursaria com linfócitos atípicos e quadro agudo autolimitado, não uma linfocitose persistente e assintomática dessa magnitude; o linfoma de Burkitt é neoplasia agressiva que exige tratamento imediato, não observação; a reação leucemoide relaciona-se a processo infeccioso agudo, não ao achado incidental e crônico descrito.' },
  { id: 'ufsc_gerado26_082', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Geriatria', text: 'Mulher, 80 anos, queda da própria altura, dor intensa em quadril esquerdo, encurtamento e rotação externa do membro, radiografia confirmando fratura do colo do fêmur. Assinale a alternativa CORRETA sobre a conduta:', options: ['o tratamento cirúrgico precoce é preferível ao conservador, reduzindo complicações do imobilismo prolongado.', 'o tratamento conservador com repouso prolongado no leito é a conduta padrão-ouro.', 'a cirurgia deve ser postergada por, no mínimo, 30 dias em todos os casos.', 'a fratura do colo do fêmur em idosos não se associa a aumento de mortalidade.', 'a reabilitação precoce após a cirurgia deve ser evitada, para não sobrecarregar o quadril operado.'], correctIndex: 0, explanation: 'Em idosos com fratura de colo de fêmur, o tratamento cirúrgico precoce é preferível ao conservador, reduzindo complicações graves do imobilismo prolongado. O tratamento conservador não é o padrão-ouro; postergar a cirurgia por 30 dias contraria a recomendação de intervenção precoce; essa fratura está associada a aumento significativo de mortalidade; a reabilitação precoce é recomendada, não evitada.' },
  { id: 'ufsc_gerado26_083', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Reumatologia', text: 'Mulher, 50 anos, com sensação de areia nos olhos, boca seca persistente com dificuldade para deglutir alimentos secos, aumento bilateral de parótidas, anticorpos anti-Ro (SSA) e anti-La (SSB) positivos, teste de Schirmer alterado. Assinale o diagnóstico MAIS PROVÁVEL:', options: ['síndrome de Sjögren primária.', 'lúpus eritematoso sistêmico isolado, sem outra condição associada.', 'esclerose sistêmica limitada isolada.', 'sarcoidose isolada, sem relação com os achados oculares e salivares descritos.', 'artrite reumatoide isolada, sem acometimento glandular exócrino.'], correctIndex: 0, explanation: 'Xeroftalmia, xerostomia, aumento de parótidas e anticorpos anti-Ro/anti-La positivos, com teste de Schirmer alterado, confirmam síndrome de Sjögren primária, doença autoimune que acomete glândulas exócrinas. O lúpus eritematoso sistêmico isolado não explica esse conjunto específico de achados glandulares exócrinos como quadro central; a esclerose sistêmica cursa com espessamento cutâneo e Raynaud, não esse padrão de xerostomia/xeroftalmia como achado central; a sarcoidose pode cursar com aumento de parótidas em casos raros, mas não explica o perfil sorológico específico anti-Ro/anti-La; a artrite reumatoide isolada não explica o acometimento glandular exócrino descrito.' },
  { id: 'ufsc_gerado26_084', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Psiquiatria', text: 'Homem, 25 anos, com pensamentos intrusivos recorrentes sobre contaminação e rituais de lavagem das mãos por horas ao dia, reconhecendo o comportamento como excessivo. Assinale a classe medicamentosa de primeira linha:', options: ['inibidor seletivo da recaptação de serotonina, geralmente em doses mais altas que na depressão.', 'antipsicótico isolado.', 'benzodiazepínico isolado como tratamento de manutenção.', 'psicanálise isolada, sem medicação.', 'estabilizador de humor isolado, sem associação com ISRS.'], correctIndex: 0, explanation: 'No transtorno obsessivo-compulsivo, os ISRS são a primeira linha farmacológica, geralmente em doses mais altas do que as usadas na depressão. Antipsicótico isolado não é primeira linha; benzodiazepínico isolado não trata o núcleo obsessivo-compulsivo e traz risco de dependência; psicanálise isolada sem medicação não é a abordagem farmacológica de primeira linha; estabilizador de humor isolado não é a classe indicada.' },
  { id: 'ufsc_gerado26_085', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 40 anos, com queixa de dor anal intensa à evacuação, com sangramento vivo em pequena quantidade, fissura visível na linha média posterior do canal anal ao exame proctológico. Assinale a conduta inicial MAIS ADEQUADA:', options: ['tratamento clínico conservador (dieta rica em fibras, banho de assento, pomadas relaxantes do esfíncter), reservando cirurgia para casos refratários.', 'esfincterotomia lateral interna imediata, como primeira conduta em toda fissura anal aguda.', 'hemorroidectomia imediata, independente da ausência de hemorroidas identificadas.', 'apenas observação isolada, sem qualquer orientação dietética ou tratamento tópico.', 'antibioticoterapia sistêmica isolada, sem qualquer medida local.'], correctIndex: 0, explanation: 'A fissura anal aguda é tratada inicialmente de forma conservadora (fibras, banho de assento, pomadas relaxantes), reservando a esfincterotomia para casos crônicos refratários ao tratamento clínico. Esfincterotomia imediata como primeira conduta é desproporcional para fissura aguda, sem tentativa conservadora prévia; hemorroidectomia não é indicada na ausência de hemorroidas, sendo diagnóstico diferente; observação isolada sem qualquer tratamento não alivia os sintomas nem favorece a cicatrização; antibioticoterapia sistêmica isolada não é o tratamento primário dessa condição, que não é primariamente infecciosa.' },
  { id: 'ufsc_gerado26_086', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 55 anos, com queixa de perda involuntária de urina aos esforços (tosse, espirro), sem perda associada à urgência miccional, exame físico com hipermobilidade do colo vesical. Assinale a hipótese diagnóstica e a conduta inicial:', options: ['incontinência urinária de esforço; fisioterapia do assoalho pélvico como primeira linha.', 'bexiga hiperativa; anticolinérgico como primeira linha, independente do padrão de perda urinária.', 'incontinência por transbordamento; cateterismo intermitente definitivo, sem outra investigação.', 'fístula vesicovaginal; correção cirúrgica imediata, sem tentativa conservadora prévia.', 'infecção do trato urinário; antibioticoterapia isolada, sem qualquer avaliação urodinâmica.'], correctIndex: 0, explanation: 'Perda urinária aos esforços, sem urgência miccional associada, com hipermobilidade do colo vesical, é característica da incontinência urinária de esforço, tratada inicialmente com fisioterapia do assoalho pélvico. A bexiga hiperativa cursa com urgência miccional proeminente, ausente no caso; a incontinência por transbordamento relaciona-se a retenção urinária crônica, com quadro clínico diferente; a fístula vesicovaginal cursaria com perda urinária contínua, não relacionada a esforços; infecção do trato urinário não explica esse padrão específico de perda relacionada a esforço físico.' },
  { id: 'ufsc_gerado26_087', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 35 anos, com dor anal intensa, febre e abaulamento doloroso e flutuante próximo à margem anal, sem drenagem espontânea de secreção. Assinale a conduta MAIS ADEQUADA:', options: ['drenagem cirúrgica do abscesso perianal, associada a antibioticoterapia conforme o contexto clínico.', 'apenas antibioticoterapia oral isolada, sem qualquer drenagem cirúrgica.', 'observação clínica isolada por 7 dias, aguardando drenagem espontânea.', 'fistulotomia imediata, independente da presença de trajeto fistuloso já estabelecido.', 'apenas banho de assento e analgesia, sem qualquer intervenção cirúrgica.'], correctIndex: 0, explanation: 'Abscesso perianal com flutuação exige drenagem cirúrgica, associada a antibioticoterapia conforme o contexto clínico (imunossupressão, celulite extensa, sinais sistêmicos). Antibioticoterapia oral isolada, sem drenagem, é insuficiente diante de coleção purulenta já organizada; aguardar drenagem espontânea por 7 dias prolonga a dor e o risco de complicações; a fistulotomia é indicada apenas quando há trajeto fistuloso já estabelecido, geralmente identificado após a drenagem do abscesso agudo, não sendo a conduta imediata nesse momento; banho de assento e analgesia isolados não tratam a coleção purulenta que exige drenagem.' },
  { id: 'ufsc_gerado26_088', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 65 anos, histerectomizada há 10 anos, refere sensação de peso vaginal e percepção de "bola" saindo pela vagina, que piora ao final do dia e aos esforços, exame físico confirmando protrusão da cúpula vaginal além do intróito. Assinale a conduta inicial MAIS ADEQUADA:', options: ['fisioterapia do assoalho pélvico ou pessário vaginal, reservando a cirurgia de correção para casos refratários ou de maior gravidade.', 'histerectomia de repetição, independente de a paciente já ter sido histerectomizada previamente.', 'observação isolada, sem qualquer orientação ou tratamento, independente dos sintomas relatados.', 'cirurgia de correção do prolapso como única conduta possível, sem qualquer tentativa conservadora prévia.', 'antibioticoterapia empírica isolada, considerando infecção como única hipótese diagnóstica.'], correctIndex: 0, explanation: 'Prolapso de cúpula vaginal sintomático pode ser inicialmente conduzido com fisioterapia do assoalho pélvico ou pessário, reservando a cirurgia para casos refratários ou mais graves. Histerectomia de repetição não é aplicável, pois o útero já foi removido, sendo o prolapso de cúpula uma condição distinta; observação isolada ignora os sintomas relatados que afetam a qualidade de vida; a cirurgia não é a única conduta possível, havendo opções conservadoras eficazes antes dela; antibioticoterapia não trata um prolapso de órgão pélvico, que não é uma condição infecciosa.' },
  { id: 'ufsc_gerado26_089', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 29 anos, diabética em uso recente de antibiótico de amplo espectro para sinusite, apresenta corrimento vaginal branco, espesso, em grumos ("leite coalhado"), prurido vulvar intenso e hiperemia da mucosa vaginal, pH vaginal normal (4,0). Assinale o diagnóstico MAIS PROVÁVEL e o tratamento:', options: ['candidíase vulvovaginal; antifúngico tópico ou oral, sem necessidade de tratar o parceiro sexual assintomático.', 'vaginose bacteriana; metronidazol, com necessidade de tratar o parceiro sexual em todos os casos.', 'tricomoníase; metronidazol, sem qualquer relação com pH vaginal normal.', 'cervicite gonocócica; ceftriaxona isolada, sem relação com o aspecto do corrimento descrito.', 'vaginite atrófica; estrogênio tópico isolado, independente da idade reprodutiva da paciente.'], correctIndex: 0, explanation: 'Corrimento em grumos, prurido intenso e pH vaginal normal são característicos da candidíase vulvovaginal, favorecida por diabetes e uso recente de antibiótico, tratada com antifúngico tópico ou oral, sem necessidade de tratar parceiro assintomático de rotina. A vaginose bacteriana cursa com corrimento acinzentado de odor fétido e pH elevado, não esse aspecto em grumos; a tricomoníase cursa com pH vaginal elevado, diferente do relatado; a cervicite gonocócica não explica o aspecto em grumos do corrimento; a vaginite atrófica ocorre em hipoestrogenismo (menopausa), não sendo a hipótese mais provável em mulher de 29 anos.' },
  { id: 'ufsc_gerado26_090', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Criança de 7 anos, com deformidade em "sabre" de tíbias, ceratite intersticial bilateral e incisivos superiores centrais com entalhe central (dentes de Hutchinson), história materna de sífilis não tratada na gestação. Assinale o diagnóstico e a implicação desses achados:', options: ['sífilis congênita tardia; os estigmas (tríade de Hutchinson e tíbia em sabre) são sequelas de infecção não tratada ou tratada tardiamente na gestação.', 'raquitismo carencial isolado, sem qualquer relação com infecção congênita.', 'osteogênese imperfeita isolada, sem relação com a história materna de sífilis.', 'displasia ectodérmica isolada, sem relação com a tríade descrita.', 'sequela de rubéola congênita, sem relação com os achados descritos.'], correctIndex: 0, explanation: 'A tríade de Hutchinson (ceratite intersticial, dentes de Hutchinson e alterações ósseas como tíbia em sabre) caracteriza estigmas da sífilis congênita tardia, decorrentes de infecção não tratada ou tratada tardiamente durante a gestação. O raquitismo carencial não explica a ceratite intersticial nem os dentes de Hutchinson; a osteogênese imperfeita cursaria com fraturas de repetição e escleras azuladas, não esse conjunto específico de achados; a displasia ectodérmica não explica a ceratite nem a deformidade tibial descrita; a rubéola congênita cursa com outros estigmas (catarata, surdez, cardiopatia), não a tríade de Hutchinson.' },
  { id: 'ufsc_gerado26_091', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 42 anos, com massa em mama direita há 3 meses, ultrassonografia evidenciando cisto complexo com componente sólido intracístico. Assinale a conduta MAIS ADEQUADA:', options: ['biópsia percutânea do componente sólido, dada a suspeição imposta por esse achado.', 'aspiração isolada do conteúdo cístico, sem biópsia do componente sólido.', 'observação clínica isolada por 6 meses, sem qualquer investigação adicional.', 'mastectomia imediata, sem confirmação histológica prévia.', 'apenas seguimento com nova ultrassonografia em 12 meses, sem biópsia.'], correctIndex: 0, explanation: 'Cisto complexo com componente sólido intracístico é achado com suspeição aumentada, exigindo biópsia percutânea do componente sólido para excluir malignidade. Aspirar isoladamente o conteúdo cístico sem biopsiar o componente sólido deixa a suspeita não investigada; observação isolada por 6 meses atrasa o diagnóstico diante de achado suspeito; mastectomia sem confirmação histológica é desproporcional; seguimento sem biópsia não é apropriado diante desse achado de maior suspeição.' },
  { id: 'ufsc_gerado26_092', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 58 anos, com hematoquezia intermitente, colonoscopia evidenciando múltiplos pólipos colônicos (mais de 100), história familiar de polipose e câncer colorretal precoce. Assinale a hipótese diagnóstica MAIS PROVÁVEL e a conduta:', options: ['polipose adenomatosa familiar; colectomia profilática, dado o altíssimo risco de malignização.', 'síndrome de Peutz-Jeghers; observação isolada, sem necessidade de qualquer conduta cirúrgica.', 'polipose juvenil isolada, sem risco aumentado de malignização, sem necessidade de seguimento.', 'doença diverticular extensa, sem qualquer relação com risco de câncer colorretal.', 'hemorroidas internas isoladas, sem relação com os pólipos identificados.'], correctIndex: 0, explanation: 'Múltiplos pólipos adenomatosos (mais de 100) com história familiar de polipose e câncer colorretal precoce são característicos da polipose adenomatosa familiar, condição com altíssimo risco de malignização que geralmente indica colectomia profilática. A síndrome de Peutz-Jeghers cursa com pólipos hamartomatosos e pigmentação mucocutânea característica, distinta desse quadro; a polipose juvenil isolada tem menor número de pólipos e ainda assim carrega risco aumentado de câncer, não sendo isenta de seguimento; a doença diverticular não explica múltiplos pólipos adenomatosos; hemorroidas internas não explicam o achado colonoscópico de múltiplos pólipos.' },
  { id: 'ufsc_gerado26_093', banca: 'UFSC', cycle: 'Ciclo Clínico', subject: 'Medicina de Família/SUS', text: 'Em relação à Rede Cegonha, política de atenção à saúde materno-infantil no SUS, assinale a alternativa CORRETA:', options: ['busca garantir acesso, acolhimento e resolutividade no pré-natal, parto, puerpério e primeiros anos de vida da criança.', 'restringe-se exclusivamente ao acompanhamento do parto hospitalar, sem relação com o pré-natal.', 'não estabelece qualquer meta relacionada à redução da mortalidade materna e infantil.', 'é aplicável apenas a gestantes de alto risco, excluindo gestantes de risco habitual.', 'substitui integralmente a necessidade de acompanhamento pela atenção primária à saúde.'], correctIndex: 0, explanation: 'A Rede Cegonha busca garantir acesso, acolhimento e resolutividade em todo o ciclo gravídico-puerperal e nos primeiros anos de vida da criança. Não se restringe ao parto hospitalar, incluindo o pré-natal e o puerpério; estabelece sim metas relacionadas à redução da mortalidade materna e infantil, sendo esse um de seus objetivos centrais; aplica-se a gestantes de risco habitual e de alto risco, não sendo exclusiva de um grupo; não substitui o acompanhamento pela atenção primária, articulando-se com ela.' },
  { id: 'ufsc_gerado26_094', banca: 'UFSC', cycle: 'Ciclo Básico', subject: 'Epidemiologia', text: 'Em um município com 4.000 nascidos vivos em um ano, ocorreram 32 óbitos de menores de 1 ano no mesmo período. Assinale o coeficiente de mortalidade infantil desse município nesse ano:', options: ['8 por 1.000 nascidos vivos.', '32 por 1.000 nascidos vivos.', '0,8 por 1.000 nascidos vivos.', '80 por 1.000 nascidos vivos.', '4 por 1.000 nascidos vivos.'], correctIndex: 0, explanation: 'O coeficiente de mortalidade infantil é o número de óbitos de menores de 1 ano dividido pelo número de nascidos vivos no mesmo período, multiplicado por 1.000 (32/4.000 x 1.000 = 8 por 1.000 nascidos vivos). Usar 32 diretamente ignora a necessidade de relativizar ao número de nascidos vivos; 0,8 e 80 correspondem a erros de posicionamento decimal no cálculo; 4 não corresponde ao resultado correto da divisão proposta.' },
  { id: 'ufsc_gerado26_095', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 60 anos, com massa cervical anterior de crescimento progressivo, ultrassonografia de tireoide classificando o nódulo como alto risco (TI-RADS 5). Assinale a próxima etapa de investigação MAIS APROPRIADA:', options: ['punção aspirativa por agulha fina do nódulo, guiada por ultrassonografia.', 'tireoidectomia total imediata, sem qualquer confirmação citológica prévia.', 'observação clínica isolada, sem qualquer investigação adicional.', 'radioterapia isolada, sem avaliação cirúrgica ou citológica prévia.', 'cintilografia como único exame necessário, sem punção.'], correctIndex: 0, explanation: 'Nódulo de alto risco ultrassonográfico tem indicação de punção aspirativa por agulha fina guiada por imagem. Tireoidectomia sem confirmação citológica prévia é desproporcional; observação isolada ignora as características de alto risco; radioterapia isolada não é conduta inicial apropriada; cintilografia é mais útil em nódulos hiperfuncionantes, não substituindo a punção nesse contexto.' },
  { id: 'ufsc_gerado26_096', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Mulher, 24 anos, com atraso menstrual, teste de gravidez positivo, cólicas leves e sangramento vaginal discreto, colo uterino fechado ao exame especular, ultrassonografia com saco gestacional intrauterino e embrião com batimentos cardíacos presentes. Assinale a conduta MAIS ADEQUADA:', options: ['conduta expectante, com repouso relativo e reavaliação, dado o colo fechado e a viabilidade embrionária confirmada.', 'curetagem uterina imediata, dado o sangramento vaginal já presente.', 'internação obrigatória até a resolução completa do sangramento, independente da evolução clínica.', 'interrupção da gestação, dado o risco de aborto já estabelecido.', 'antibioticoterapia sistêmica isolada, sem relação com a viabilidade embrionária.'], correctIndex: 0, explanation: 'Ameaça de abortamento, com colo fechado e viabilidade embrionária confirmada (batimentos cardíacos presentes), é conduzida de forma expectante, com repouso relativo e reavaliação. Curetagem uterina imediata é desproporcional diante de gestação viável e colo fechado; internação obrigatória não é necessária para todo caso de sangramento discreto com colo fechado; interrupção da gestação não é indicada diante de viabilidade confirmada; antibioticoterapia sistêmica isolada não tem relação com essa apresentação clínica, que não é infecciosa.' },
  { id: 'ufsc_gerado26_097', banca: 'UFSC', cycle: 'Internato', subject: 'Pediatria', text: 'Lactente, 8 meses, com tosse, coriza e sibilância há 2 dias, desconforto respiratório leve, primeiro episódio de sibilância, teste rápido positivo para vírus sincicial respiratório. Assinale a conduta:', options: ['suporte com lavagem nasal, oxigenoterapia se necessário e hidratação, sem broncodilatador, corticoide ou antibiótico de rotina.', 'corticoide sistêmico em dose única, indicado rotineiramente para reduzir o tempo de internação.', 'antibioticoterapia empírica de rotina, dada a alta taxa de coinfecção bacteriana.', 'broncodilatador inalatório de rotina e continuado em todos os casos.', 'internação obrigatória em UTI, independente da gravidade do desconforto respiratório.'], correctIndex: 0, explanation: 'O tratamento da bronquiolite viral aguda é essencialmente de suporte, sem benefício comprovado de broncodilatador, corticoide ou antibiótico de rotina. Corticoide sistêmico não reduz tempo de internação; antibioticoterapia empírica não é indicada sem sinais de infecção bacteriana; broncodilatador de rotina não tem eficácia comprovada; internação em UTI não é obrigatória para todo caso.' },
  { id: 'ufsc_gerado26_098', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Mulher, 68 anos, com dor abdominal difusa, distensão e parada de eliminação de gases e fezes há 3 dias, radiografia de abdome evidenciando alça sigmoide muito dilatada em formato de "grão de café", sem sinais de irritação peritoneal. Assinale a conduta inicial MAIS ADEQUADA:', options: ['descompressão endoscópica (retossigmoidoscopia com sonda retal), reservando cirurgia para casos refratários ou com sinais de complicação.', 'colectomia de urgência imediata em todos os casos, sem tentativa de descompressão endoscópica.', 'apenas laxante oral isolado, sem qualquer investigação radiológica ou endoscópica.', 'observação clínica isolada por 7 dias, sem qualquer intervenção descompressiva.', 'colonoscopia total sob sedação profunda como primeira conduta, independente do risco de perfuração em alça muito dilatada.'], correctIndex: 0, explanation: 'O quadro radiológico e clínico é compatível com volvo de sigmoide, cuja conduta inicial na ausência de sinais de irritação peritoneal é a descompressão endoscópica, reservando cirurgia para casos refratários ou complicados. Colectomia de urgência imediata em todos os casos é desproporcional quando a descompressão endoscópica é factível e segura; laxante oral isolado não resolve uma obstrução mecânica por volvo; observação isolada por 7 dias arrisca isquemia e perfuração da alça dilatada; colonoscopia total sob sedação profunda, sem a técnica dirigida e cautelosa de descompressão, aumenta desnecessariamente o risco de perfuração em alça muito dilatada.' },
  { id: 'ufsc_gerado26_099', banca: 'UFSC', cycle: 'Internato', subject: 'Ginecologia & Obstetrícia', text: 'Gestante, 38 semanas, em trabalho de parto, cardiotocografia evidenciando desacelerações tardias repetidas associadas a contrações uterinas regulares. Assinale a interpretação MAIS PROVÁVEL e a conduta:', options: ['sugestivo de insuficiência uteroplacentária; medidas de ressuscitação intrauterina e avaliação para resolução do parto conforme resposta.', 'padrão normal e tranquilizador, sem necessidade de qualquer intervenção.', 'desacelerações precoces por compressão da cabeça fetal, sem necessidade de qualquer conduta adicional.', 'desacelerações variáveis por compressão de cordão, sem relação com oxigenação fetal.', 'taquissistolia uterina isolada, sem qualquer relação com o padrão de frequência cardíaca fetal.'], correctIndex: 0, explanation: 'Desacelerações tardias repetidas sugerem insuficiência uteroplacentária, exigindo medidas de ressuscitação intrauterina e avaliação para resolução do parto conforme a resposta. Não é padrão normal e tranquilizador; desacelerações precoces têm relação com a fase da contração e compressão cefálica, timing diferente das tardias; desacelerações variáveis relacionam-se à compressão de cordão, mas o padrão descrito é de desacelerações tardias; taquissistolia é achado distinto, não sinônimo do padrão descrito.' },
  { id: 'ufsc_gerado26_100', banca: 'UFSC', cycle: 'Internato', subject: 'Cirurgia Geral', text: 'Homem, 55 anos, etilista, com hematêmese de pequeno volume, epigastralgia após vômitos repetidos e história de libação alcoólica recente, endoscopia evidenciando laceração longitudinal na transição esofagogástrica, sem sangramento ativo no momento do exame. Assinale o diagnóstico e a conduta:', options: ['síndrome de Mallory-Weiss; tratamento conservador na maioria dos casos, dado o caráter frequentemente autolimitado do sangramento.', 'síndrome de Boerhaave; cirurgia de urgência para reparo da perfuração transmural.', 'varizes esofágicas sangrantes; ligadura elástica endoscópica imediata, independente dos achados descritos.', 'úlcera péptica perfurada; laparotomia de urgência, independente da ausência de sinais de irritação peritoneal.', 'câncer gástrico ulcerado; biópsia isolada, sem qualquer conduta relacionada ao sangramento agudo.'], correctIndex: 0, explanation: 'Laceração longitudinal na transição esofagogástrica após vômitos repetidos é o quadro clássico da síndrome de Mallory-Weiss, geralmente autolimitada e tratada de forma conservadora. A síndrome de Boerhaave envolve perfuração transmural completa do esôfago, com quadro muito mais grave (dor torácica intensa, enfisema subcutâneo), exigindo cirurgia de urgência, diferente da laceração superficial descrita; varizes esofágicas teriam aspecto endoscópico distinto (cordões varicosos), não uma laceração linear na transição esofagogástrica; úlcera péptica perfurada cursaria com sinais de irritação peritoneal e pneumoperitônio, ausentes no caso; câncer gástrico ulcerado não é o achado endoscópico descrito, que é uma laceração aguda, não uma lesão neoplásica.' },
];
